fn parse_scenario(path: &Path) -> RuntimeResult<Scenario> {
    let text = fs::read_to_string(path)?;
    Ok(toml::from_str(&text)?)
}

fn toml_string_ref<'a>(table: &'a BTreeMap<String, toml::Value>, key: &str) -> Option<&'a str> {
    table.get(key).and_then(toml::Value::as_str)
}

fn toml_usize_ref(table: &BTreeMap<String, toml::Value>, key: &str) -> Option<usize> {
    table
        .get(key)
        .and_then(toml::Value::as_integer)
        .and_then(|value| usize::try_from(value).ok())
}

fn toml_u64_ref(table: &BTreeMap<String, toml::Value>, key: &str) -> Option<u64> {
    table
        .get(key)
        .and_then(toml::Value::as_integer)
        .and_then(|value| u64::try_from(value).ok())
}

pub fn enrich_runtime_execution_surface(report: &mut JsonValue, layer: &str) {
    let Some(object) = report.as_object_mut() else {
        return;
    };
    object.insert("window_mode".to_owned(), runtime_window_mode(layer));
    object.insert("window_backend".to_owned(), runtime_window_backend(layer));
    object.insert("display_server".to_owned(), json!(display_server()));
}

fn runtime_window_mode(layer: &str) -> JsonValue {
    match layer {
        "semantic" | "speed" => json!("none"),
        _ => json!("not-applicable"),
    }
}

fn runtime_window_backend(layer: &str) -> JsonValue {
    match layer {
        "semantic" | "speed" => {
            json!({"unavailable_reason": "semantic/runtime layer does not open a window"})
        }
        _ => json!("not-applicable"),
    }
}

fn display_server() -> String {
    if std::env::var("WAYLAND_DISPLAY").is_ok() {
        "wayland".to_owned()
    } else if std::env::var("DISPLAY").is_ok() {
        "x11".to_owned()
    } else {
        "none".to_owned()
    }
}

pub fn write_json(path: &Path, value: &JsonValue) -> RuntimeResult<()> {
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }
    fs::write(path, serde_json::to_vec_pretty(value)?)?;
    Ok(())
}

pub fn sha256_bytes(bytes: &[u8]) -> String {
    let mut hasher = Sha256::new();
    hasher.update(bytes);
    format!("{:x}", hasher.finalize())
}

pub fn sha256_file(path: &Path) -> RuntimeResult<String> {
    if fs::metadata(path)
        .map(|metadata| metadata.len())
        .unwrap_or(0)
        >= 8 * 1024 * 1024
    {
        if let Some(hash) = sha256_file_with_system_tool(path) {
            return Ok(hash);
        }
    }
    let file = fs::File::open(path)?;
    let mut reader = BufReader::new(file);
    let mut hasher = Sha256::new();
    let mut buffer = [0u8; 64 * 1024];
    loop {
        let read = reader.read(&mut buffer)?;
        if read == 0 {
            break;
        }
        hasher.update(&buffer[..read]);
    }
    Ok(format!("{:x}", hasher.finalize()))
}

fn sha256_file_with_system_tool(path: &Path) -> Option<String> {
    let tool = ["/usr/bin/sha256sum", "/bin/sha256sum"]
        .into_iter()
        .map(Path::new)
        .find(|candidate| candidate.is_file())?;
    let output = Command::new(tool).arg("--").arg(path).output().ok()?;
    if !output.status.success() {
        return None;
    }
    let stdout = String::from_utf8(output.stdout).ok()?;
    let hash = stdout.split_whitespace().next()?.to_ascii_lowercase();
    if is_sha256_hex(&hash) {
        Some(hash)
    } else {
        None
    }
}

fn cached_report_binary_hash(path: &Path) -> RuntimeResult<String> {
    let cache = REPORT_BINARY_HASH_CACHE.get_or_init(|| Mutex::new(BTreeMap::new()));
    if let Some(hash) = cache
        .lock()
        .map_err(|error| format!("report binary hash cache is poisoned: {error}"))?
        .get(path)
        .cloned()
    {
        return Ok(hash);
    }
    let hash = sha256_file(path)?;
    cache
        .lock()
        .map_err(|error| format!("report binary hash cache is poisoned: {error}"))?
        .insert(path.to_path_buf(), hash.clone());
    Ok(hash)
}

pub fn report_schema_hash() -> String {
    sha256_bytes(include_str!("lib.rs").as_bytes())
}

const VERIFIER_IDENTITY_KIND: &str = "xtask-verifier-contract";
const VERIFIER_IDENTITY_SCHEME_VERSION: u64 = 1;
const NATIVE_GPU_VERIFIER_CONTRACT_VERSION: &str = "native-gpu-control-plane-2026-07-05.1";
const BYTES_MACHINE_PLAN_VERIFIER_CONTRACT_VERSION: &str =
    "bytes-machine-plan-control-plane-2026-07-06.1";

fn verifier_identity_contract_version(command: &str) -> Option<&'static str> {
    if command_supports_native_scoped_verifier_identity(command) {
        Some(NATIVE_GPU_VERIFIER_CONTRACT_VERSION)
    } else if command_supports_bytes_scoped_verifier_identity(command) {
        Some(BYTES_MACHINE_PLAN_VERIFIER_CONTRACT_VERSION)
    } else {
        None
    }
}

fn command_supports_native_scoped_verifier_identity(command: &str) -> bool {
    command == "verify-platform-contract"
        || command == "verify-wgpu-readback"
        || command == "verify-wgpu-retained-arenas"
        || command == "verify-demand-driven-render-loop"
        || command == "verify-native-gpu-all"
        || command.starts_with("verify-native-")
        || command.starts_with("verify-native-gpu-")
}

fn command_supports_bytes_scoped_verifier_identity(command: &str) -> bool {
    matches!(
        command,
        "dump-plan"
            | "run-plan"
            | "run-plan-route"
            | "run-plan-root-scalar-scenario"
            | "run-plan-scenario-events"
            | "bytes-plan-phase0-baseline"
            | "verify-build-bytes-boundary"
            | "verify-bytes-machine-plan-all"
    ) || command.starts_with("verify-bytes-")
}

fn canonical_verifier_args(command: &str, args: &[String]) -> Vec<String> {
    let mut start = args
        .iter()
        .position(|arg| arg == command)
        .map_or(0, |index| index.saturating_add(1));
    if command == "run-plan-scenario-events" && start == 0 {
        start = args
            .iter()
            .position(|arg| arg == "run")
            .map_or(0, |index| index.saturating_add(1));
    }
    if start == 0
        && args
            .first()
            .and_then(|arg| Path::new(arg).file_stem())
            .and_then(std::ffi::OsStr::to_str)
            .is_some_and(|stem| {
                stem == "xtask"
                    || stem == "xtask.exe"
                    || stem == "boon_cli"
                    || stem == "boon_cli.exe"
            })
    {
        start = 1;
        if args.get(start).is_some_and(|arg| {
            arg == command || (command == "run-plan-scenario-events" && arg == "run")
        }) {
            start = start.saturating_add(1);
        }
    }
    let mut canonical = Vec::new();
    let mut index = start;
    while index < args.len() {
        let arg = &args[index];
        if arg == "--report" {
            index = index.saturating_add(2);
            continue;
        }
        if arg.starts_with("--report=") {
            index = index.saturating_add(1);
            continue;
        }
        if command == "verify-native-gpu-present-floor" && arg == "--inner-app-window" {
            index = index.saturating_add(1);
            continue;
        }
        canonical.push(arg.clone());
        index = index.saturating_add(1);
    }
    canonical
}

fn verifier_identity_hash(
    command: &str,
    measurement_mode: &str,
    contract_version: &str,
    canonical_args: &[String],
) -> String {
    let mut material = Vec::new();
    let scheme_version = VERIFIER_IDENTITY_SCHEME_VERSION.to_string();
    for part in [
        VERIFIER_IDENTITY_KIND,
        scheme_version.as_str(),
        command,
        measurement_mode,
        contract_version,
    ] {
        material.extend_from_slice(part.as_bytes());
        material.push(0);
    }
    for arg in canonical_args {
        material.extend_from_slice(arg.as_bytes());
        material.push(0);
    }
    sha256_bytes(&material)
}

fn verifier_identity_for_command_args(
    command: &str,
    measurement_mode: &str,
    args: &[String],
) -> Option<JsonValue> {
    let contract_version = verifier_identity_contract_version(command)?;
    let canonical_args = canonical_verifier_args(command, args);
    let canonical_args_hash = sha256_bytes(canonical_args.join("\0").as_bytes());
    let identity_hash =
        verifier_identity_hash(command, measurement_mode, contract_version, &canonical_args);
    Some(json!({
        "kind": VERIFIER_IDENTITY_KIND,
        "scheme_version": VERIFIER_IDENTITY_SCHEME_VERSION,
        "command": command,
        "measurement_mode": measurement_mode,
        "contract_version": contract_version,
        "canonical_args": canonical_args,
        "canonical_args_hash": canonical_args_hash,
        "identity_hash": identity_hash,
        "binary_hash_policy": "binary-hash-may-be-superseded-by-matching-verifier-identity"
    }))
}

fn report_verifier_identity_matches_report(report: &JsonValue) -> bool {
    let Some(command) = report.get("command").and_then(JsonValue::as_str) else {
        return false;
    };
    let Some(measurement_mode) = report.get("measurement_mode").and_then(JsonValue::as_str) else {
        return false;
    };
    let Some(args) = report.get("command_argv").and_then(JsonValue::as_array) else {
        return false;
    };
    let Some(args) = args
        .iter()
        .map(|arg| arg.as_str().map(str::to_owned))
        .collect::<Option<Vec<_>>>()
    else {
        return false;
    };
    let Some(expected) = verifier_identity_for_command_args(command, measurement_mode, &args)
    else {
        return false;
    };
    report.get("verifier_identity") == Some(&expected)
}

const SOURCE_REPLAY_IDENTITY_KIND: &str = "plan-executor-source-replay-contract";
const SOURCE_REPLAY_IDENTITY_SCHEME_VERSION: u64 = 1;
const SOURCE_REPLAY_CONTRACT_VERSION: &str = "plan-executor-source-replay-2026-07-05.1";

fn canonical_source_replay_args(args: &[String]) -> Vec<String> {
    let mut canonical = Vec::new();
    let mut index = 0;
    while index < args.len() {
        let arg = &args[index];
        if arg == "--report" {
            index = index.saturating_add(2);
            continue;
        }
        if arg.starts_with("--report=") {
            index = index.saturating_add(1);
            continue;
        }
        canonical.push(arg.clone());
        index = index.saturating_add(1);
    }
    canonical
}

fn json_value_hash(value: &JsonValue) -> Option<String> {
    serde_json::to_vec(value)
        .ok()
        .map(|bytes| sha256_bytes(&bytes))
}

fn source_replay_identity_for_report(report: &JsonValue) -> Option<JsonValue> {
    let command = report.get("command").and_then(JsonValue::as_str)?;
    if command != "run-plan-scenario-events" {
        return None;
    }
    let measurement_mode = report.get("measurement_mode").and_then(JsonValue::as_str)?;
    let args = report.get("command_argv").and_then(JsonValue::as_array)?;
    let args = args
        .iter()
        .map(|arg| arg.as_str().map(str::to_owned))
        .collect::<Option<Vec<_>>>()?;
    if args
        .iter()
        .any(|arg| arg == "--engine" || arg.starts_with("--engine="))
    {
        return None;
    }
    let canonical_args = canonical_source_replay_args(&args);
    let canonical_args_hash = sha256_bytes(canonical_args.join("\0").as_bytes());
    let source_hash = report.get("source_hash").and_then(JsonValue::as_str)?;
    let scenario_hash = report.get("scenario_hash").and_then(JsonValue::as_str)?;
    let target_profile = report.get("target_profile").and_then(JsonValue::as_str)?;
    let plan_hash = report.get("plan_hash").and_then(JsonValue::as_str)?;
    let plan_version_hash = json_value_hash(report.get("plan_version")?)?;
    let selected_step_ids_hash = json_value_hash(report.get("selected_step_ids")?)?;
    let plan_executor_coverage_hash = json_value_hash(report.get("plan_executor_coverage")?)?;

    let mut material = Vec::new();
    let scheme_version = SOURCE_REPLAY_IDENTITY_SCHEME_VERSION.to_string();
    for part in [
        SOURCE_REPLAY_IDENTITY_KIND,
        scheme_version.as_str(),
        command,
        measurement_mode,
        SOURCE_REPLAY_CONTRACT_VERSION,
        canonical_args_hash.as_str(),
        source_hash,
        scenario_hash,
        target_profile,
        plan_hash,
        plan_version_hash.as_str(),
        selected_step_ids_hash.as_str(),
        plan_executor_coverage_hash.as_str(),
    ] {
        material.extend_from_slice(part.as_bytes());
        material.push(0);
    }
    let identity_hash = sha256_bytes(&material);

    Some(json!({
        "kind": SOURCE_REPLAY_IDENTITY_KIND,
        "scheme_version": SOURCE_REPLAY_IDENTITY_SCHEME_VERSION,
        "command": command,
        "measurement_mode": measurement_mode,
        "contract_version": SOURCE_REPLAY_CONTRACT_VERSION,
        "canonical_args": canonical_args,
        "canonical_args_hash": canonical_args_hash,
        "source_hash": source_hash,
        "scenario_hash": scenario_hash,
        "target_profile": target_profile,
        "plan_hash": plan_hash,
        "plan_version_hash": plan_version_hash,
        "selected_step_ids_hash": selected_step_ids_hash,
        "plan_executor_coverage_hash": plan_executor_coverage_hash,
        "identity_hash": identity_hash,
        "binary_hash_policy": "binary-hash-remains-schema-owned; source replay identity is control-plane evidence"
    }))
}

fn report_source_replay_identity_matches_report(report: &JsonValue) -> bool {
    let Some(expected) = source_replay_identity_for_report(report) else {
        return false;
    };
    report.get("source_replay_identity") == Some(&expected)
}

pub fn verify_report_schema(path: &Path) -> RuntimeResult<()> {
    let report: JsonValue = serde_json::from_slice(&fs::read(path)?)?;
    if report.get("command").and_then(JsonValue::as_str) == Some("compile-artifact") {
        verify_compiled_artifact_report(&report, path)?;
        return Ok(());
    }
    if report.get("command").and_then(JsonValue::as_str) == Some("inspect-compiled-artifact") {
        verify_inspected_compiled_artifact_report(&report, path)?;
        return Ok(());
    }
    if report.get("command").and_then(JsonValue::as_str)
        == Some("verify-compiled-artifact-scenario")
    {
        verify_compiled_artifact_scenario_report(&report, path)?;
        return Ok(());
    }
    if report.get("command").and_then(JsonValue::as_str) == Some("verify-bytecode") {
        verify_bytecode_report(&report, path)?;
        return Ok(());
    }
    let required = [
        "report_version",
        "generated_at_utc",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "git_commit",
        "binary_hash",
        "source_hash",
        "scenario_hash",
        "program_hash",
        "budget_hash",
        "graph_node_count",
        "per_step_pass_fail",
        "artifact_sha256s",
    ];
    for key in required {
        if report.get(key).is_none() {
            return Err(format!("{} missing required report field `{key}`", path.display()).into());
        }
    }
    if report_command_is(&report, "dump-plan") {
        verify_machine_plan_report(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_dump_plan_source_files(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "run-plan") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!("{} run-plan report did not pass", path.display()).into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_run_plan_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "run-plan-route") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!("{} run-plan-route report did not pass", path.display()).into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_run_plan_route_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "run-plan-root-scalar-scenario") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} run-plan-root-scalar-scenario report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
        verify_run_plan_root_scalar_scenario_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "run-plan-scenario-events") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} run-plan-scenario-events report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
        verify_run_plan_scenario_events_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-file-read-plan") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-file-read-plan report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
        verify_bytes_file_read_plan_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-file-write-plan") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-file-write-plan report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
        verify_bytes_file_write_plan_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-negative") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-negative report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_negative_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-type-system") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-type-system report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_report_file_hash(&report, path, "source_path", "source_hash")?;
        verify_bytes_type_system_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-default-engine-readiness")
        && report.get("status").and_then(JsonValue::as_str) == Some("pass")
    {
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_default_engine_readiness_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-machine-plan-adversarial") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-machine-plan-adversarial report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_machine_plan_adversarial_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-release-benchmark-reproduction")
        && report.get("status").and_then(JsonValue::as_str) == Some("pass")
    {
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_release_benchmark_reproduction_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-storage-profile") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-storage-profile report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_storage_profile_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-fixed-warm-tick") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-fixed-warm-tick report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_fixed_warm_tick_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-byte-bank-layout") {
        if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} verify-bytes-byte-bank-layout report did not pass",
                path.display()
            )
            .into());
        }
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_byte_bank_layout_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-bytes-machine-plan-all")
        && report.get("status").and_then(JsonValue::as_str) == Some("pass")
    {
        verify_common_report_shape(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_bytes_machine_plan_all_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-native-gpu-all") {
        let status = report.get("status").and_then(JsonValue::as_str);
        if status == Some("pass") {
            verify_common_report_shape(&report, path)?;
        } else if status == Some("fail") {
            verify_failing_blocker_report_shape(&report, path)?;
        } else {
            return Err(format!(
                "{} verify-native-gpu-all status must be pass or fail",
                path.display()
            )
            .into());
        }
        verify_measurement_mode(&report, path)?;
        verify_native_gpu_all_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "run-report-refresh-queue") {
        let status = report.get("status").and_then(JsonValue::as_str);
        if status == Some("pass") {
            verify_common_report_shape(&report, path)?;
        } else if status == Some("fail") {
            verify_failing_blocker_report_shape(&report, path)?;
        } else {
            return Err(format!(
                "{} run-report-refresh-queue status must be pass or fail",
                path.display()
            )
            .into());
        }
        verify_measurement_mode(&report, path)?;
        verify_report_refresh_queue_report(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    if report_command_is(&report, "verify-compiler-boundaries") {
        verify_compiler_boundaries_report(&report, path)?;
        verify_measurement_mode(&report, path)?;
        verify_artifact_hashes(&report, path)?;
        return Ok(());
    }
    let status = report.get("status").and_then(JsonValue::as_str);
    if status != Some("pass") {
        if status == Some("fail") && report_is_blocker_audit(&report) {
            verify_failing_blocker_report_shape(&report, path)?;
            verify_measurement_mode(&report, path)?;
            verify_artifact_hashes(&report, path)?;
            return Ok(());
        }
        return Err(format!("{} did not pass", path.display()).into());
    }
    verify_common_report_shape(&report, path)?;
    verify_measurement_mode(&report, path)?;
    verify_report_file_hash(&report, path, "source_path", "source_hash")?;
    verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
    verify_artifact_hashes(&report, path)?;
    if report_is_runtime_execution_layer(&report) {
        verify_runtime_execution_metadata(&report, path)?;
    }
    if report_command_is(&report, "verify-native-gpu-negative") {
        verify_native_gpu_negative_report(&report, path)?;
    }
    if report_is_native_gpu_command(&report) {
        verify_native_gpu_report_contract(&report, path)?;
    }
    if report.get("playground_surface").is_some() || report_layer_is(&report, "headed-smoke") {
        verify_playground_surface_report(&report, path)?;
    }
    if report_layer_is(&report, "speed") {
        verify_speed_report(&report, path)?;
    }
    if report_command_is(&report, "bench-todomvc") || report_command_is(&report, "bench-example") {
        verify_benchmark_report(&report, path)?;
    }
    Ok(())
}

pub fn verify_report_schema_negative_probe(path: &Path) -> RuntimeResult<()> {
    let report: JsonValue = serde_json::from_slice(&fs::read(path)?)?;
    if !report_command_is(&report, "verify-bytes-file-write-plan") {
        return verify_report_schema(path);
    }
    if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
        return Err(format!(
            "{} verify-bytes-file-write-plan report did not pass",
            path.display()
        )
        .into());
    }
    for key in [
        "report_version",
        "generated_at_utc",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "git_commit",
        "binary_hash",
        "source_hash",
        "scenario_hash",
        "program_hash",
        "budget_hash",
        "graph_node_count",
        "per_step_pass_fail",
        "artifact_sha256s",
    ] {
        if report.get(key).is_none() {
            return Err(format!("{} missing required report field `{key}`", path.display()).into());
        }
    }
    verify_common_report_shape(&report, path)?;
    verify_measurement_mode(&report, path)?;
    verify_report_file_hash(&report, path, "source_path", "source_hash")?;
    verify_report_file_hash(&report, path, "scenario_path", "scenario_hash")?;
    verify_bytes_file_write_plan_report_inner(&report, path, false)?;
    verify_artifact_hashes(&report, path)?;
    Ok(())
}

pub fn verify_bytes_file_write_negative_artifact(path: &Path, id: &str) -> RuntimeResult<()> {
    let report: JsonValue = serde_json::from_slice(&fs::read(path)?)?;
    verify_bytes_file_write_negative_artifact_value(&report, path, id)
}

