fn verify_bytes_type_system_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let expected = expected_bytes_type_system_check_ids();
    let required_ids = report
        .get("required_check_ids")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-type-system required_check_ids is missing",
                report_path.display()
            )
        })?
        .iter()
        .map(|value| {
            value.as_str().ok_or_else(|| {
                format!(
                    "{} verify-bytes-type-system required_check_ids contains a non-string id",
                    report_path.display()
                )
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    if required_ids.as_slice() != expected {
        return Err(format!(
            "{} verify-bytes-type-system required_check_ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    let checks = report
        .get("per_step_pass_fail")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-type-system per_step_pass_fail is missing",
                report_path.display()
            )
        })?;
    let mut check_ids = Vec::with_capacity(checks.len());
    for (index, check) in checks.iter().enumerate() {
        let object = check.as_object().ok_or_else(|| {
            format!(
                "{} verify-bytes-type-system per_step_pass_fail[{index}] is not an object",
                report_path.display()
            )
        })?;
        let id = object
            .get("id")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-type-system per_step_pass_fail[{index}] missing id",
                    report_path.display()
                )
            })?;
        if object.get("pass").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} verify-bytes-type-system check `{id}` is not passing",
                report_path.display()
            )
            .into());
        }
        let detail = object
            .get("detail")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-type-system check `{id}` missing detail",
                    report_path.display()
                )
            })?;
        if detail.trim().is_empty() {
            return Err(format!(
                "{} verify-bytes-type-system check `{id}` has empty detail",
                report_path.display()
            )
            .into());
        }
        check_ids.push(id);
    }
    if check_ids.as_slice() != expected {
        return Err(format!(
            "{} verify-bytes-type-system per_step_pass_fail ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    let type_results = report
        .get("type_results")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-type-system type_results is missing",
                report_path.display()
            )
        })?;
    if type_results.len() < 32 {
        return Err(format!(
            "{} verify-bytes-type-system type_results does not cover the BYTES builtin/refinement surface",
            report_path.display()
        )
        .into());
    }
    for (index, result) in type_results.iter().enumerate() {
        let object = result.as_object().ok_or_else(|| {
            format!(
                "{} verify-bytes-type-system type_results[{index}] is not an object",
                report_path.display()
            )
        })?;
        for key in ["kind", "name", "expected_type", "actual_type"] {
            if object
                .get(key)
                .and_then(JsonValue::as_str)
                .is_none_or(str::is_empty)
            {
                return Err(format!(
                    "{} verify-bytes-type-system type_results[{index}] missing `{key}`",
                    report_path.display()
                )
                .into());
            }
        }
        if object.get("pass").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} verify-bytes-type-system type_results[{index}] did not pass",
                report_path.display()
            )
            .into());
        }
    }
    if report
        .get("resolved_constant_count")
        .and_then(JsonValue::as_u64)
        .unwrap_or(0)
        < 7
    {
        return Err(format!(
            "{} verify-bytes-type-system resolved_constant_count is too low",
            report_path.display()
        )
        .into());
    }
    if report
        .get("typecheck_report")
        .and_then(|value| value.get("resolved_constant_table"))
        .and_then(|value| value.get("entries"))
        .and_then(JsonValue::as_array)
        .is_none_or(|entries| entries.len() < 7)
    {
        return Err(format!(
            "{} verify-bytes-type-system typecheck_report.resolved_constant_table is missing coverage",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

fn verify_bytes_default_engine_readiness_report(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    let readiness_mode = report
        .get("readiness_mode")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness readiness_mode is missing",
                report_path.display()
            )
        })?;
    if readiness_mode != "post-switch-plan-default" {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness readiness_mode `{readiness_mode}` is obsolete; only post-switch PlanExecutor default is accepted",
            report_path.display()
        )
        .into());
    }
    if report.get("readiness_scope").and_then(JsonValue::as_str)
        != Some("default-engine-control-plane-only")
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness readiness_scope must be default-engine-control-plane-only",
            report_path.display()
        )
        .into());
    }
    let expected = expected_bytes_default_engine_check_ids();
    let required = report
        .get("required_check_ids")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness required_check_ids is missing",
                report_path.display()
            )
        })?;
    let required = required
        .iter()
        .map(|item| {
            item.as_str().ok_or_else(|| {
                format!(
                    "{} verify-bytes-default-engine-readiness required_check_ids contains a non-string id",
                    report_path.display()
                )
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    if required != expected {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness required_check_ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    let steps = report
        .get("per_step_pass_fail")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness per_step_pass_fail is missing",
                report_path.display()
            )
        })?;
    let mut actual_ids = Vec::new();
    for (index, step) in steps.iter().enumerate() {
        let step = step.as_object().ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness per_step_pass_fail[{index}] is not an object",
                report_path.display()
            )
        })?;
        let id = step.get("id").and_then(JsonValue::as_str).ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness per_step_pass_fail[{index}] missing id",
                report_path.display()
            )
        })?;
        if step.get("pass").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} verify-bytes-default-engine-readiness check `{id}` is not passing",
                report_path.display()
            )
            .into());
        }
        if step
            .get("detail")
            .and_then(JsonValue::as_str)
            .unwrap_or_default()
            .is_empty()
        {
            return Err(format!(
                "{} verify-bytes-default-engine-readiness check `{id}` has empty detail",
                report_path.display()
            )
            .into());
        }
        actual_ids.push(id);
    }
    if actual_ids != expected {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness per_step_pass_fail ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    if report.get("default_engine").and_then(JsonValue::as_str) != Some("plan") {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness default_engine must be `plan` for readiness_mode `{readiness_mode}`",
            report_path.display(),
        )
        .into());
    }
    if report
        .get("default_switch_allowed")
        .and_then(JsonValue::as_bool)
        != Some(true)
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness default_switch_allowed must be true",
            report_path.display()
        )
        .into());
    }
    if !report
        .get("default_switch_blocker")
        .is_none_or(JsonValue::is_null)
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness default_switch_blocker must be null for readiness_mode `{readiness_mode}`",
            report_path.display(),
        )
        .into());
    }
    if report
        .get("diagnostic_comparison_mode")
        .and_then(JsonValue::as_str)
        != Some("not-run-not-required-for-product-readiness")
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness must keep diagnostic comparisons out of product readiness",
            report_path.display()
        )
        .into());
    }
    if report
        .get("explicit_compare_case_count")
        .and_then(JsonValue::as_u64)
        != Some(0)
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness must not run explicit compare cases",
            report_path.display()
        )
        .into());
    }
    if report
        .get("product_replay_coverage_owner")
        .and_then(JsonValue::as_str)
        != Some("native-gpu-handoff")
    {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness must leave full product replay coverage to native GPU handoff",
            report_path.display()
        )
        .into());
    }
    let delegated_reports = report
        .get("delegated_product_replay_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness delegated_product_replay_reports is missing",
                report_path.display()
            )
        })?;
    if !delegated_reports.is_empty() {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness must not delegate product replay through the BYTES control-plane report",
            report_path.display()
        )
        .into());
    }

    let children = report
        .get("child_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-default-engine-readiness child_reports is missing",
                report_path.display()
            )
        })?;
    let expected_children = vec![(
        "default-dispatch-smoke",
        "default",
        "run-plan-scenario-events",
        "default-cli-small-source-replay",
    )];
    if children.len() != expected_children.len() {
        return Err(format!(
            "{} verify-bytes-default-engine-readiness child_reports length is wrong",
            report_path.display()
        )
        .into());
    }
    for (child, (expected_id, expected_engine, expected_command, expected_coverage_mode)) in
        children.iter().zip(expected_children)
    {
        if child.get("id").and_then(JsonValue::as_str) != Some(expected_id)
            || child.get("engine").and_then(JsonValue::as_str) != Some(expected_engine)
            || child.get("expected_command").and_then(JsonValue::as_str) != Some(expected_command)
            || child.get("command").and_then(JsonValue::as_str) != Some(expected_command)
            || child.get("coverage_mode").and_then(JsonValue::as_str)
                != Some(expected_coverage_mode)
            || child
                .get("product_replay_scope")
                .and_then(JsonValue::as_str)
                != Some("small-default-dispatch-smoke")
            || child
                .get("plan_executor_status")
                .and_then(JsonValue::as_str)
                != Some("pass")
            || child
                .get("event_step_count")
                .and_then(JsonValue::as_u64)
                .is_none_or(|count| count > 2)
            || child.get("status").and_then(JsonValue::as_str) != Some("pass")
            || child.get("process_success").and_then(JsonValue::as_bool) != Some(true)
            || child.get("schema_valid").and_then(JsonValue::as_bool) != Some(true)
            || child
                .get("argv_matches_expected_command")
                .and_then(JsonValue::as_bool)
                != Some(true)
        {
            return Err(format!(
                "{} verify-bytes-default-engine-readiness child report `{expected_id}` does not match the expected command proof",
                report_path.display()
            )
            .into());
        }
        let path = child
            .get("path")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-default-engine-readiness child `{expected_id}` missing path",
                    report_path.display()
                )
            })?;
        if !Path::new(path).is_file() {
            return Err(format!(
                "{} verify-bytes-default-engine-readiness child `{expected_id}` path `{path}` is missing",
                report_path.display()
            )
            .into());
        }
    }
    Ok(())
}

fn verify_bytes_negative_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let binary_path = report
        .get("binary_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-negative report missing binary_path",
                report_path.display()
            )
        })?;
    if binary_path.trim().is_empty() {
        return Err(format!(
            "{} verify-bytes-negative report has empty binary_path",
            report_path.display()
        )
        .into());
    }

    let expected = expected_bytes_negative_case_ids();
    if report
        .get("negative_case_count")
        .and_then(JsonValue::as_u64)
        != Some(expected.len() as u64)
    {
        return Err(format!(
            "{} verify-bytes-negative negative_case_count is missing or wrong",
            report_path.display()
        )
        .into());
    }

    let required_ids = report
        .get("required_negative_cases")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-negative required_negative_cases is missing",
                report_path.display()
            )
        })?
        .iter()
        .map(|value| {
            value.as_str().ok_or_else(|| {
                format!(
                    "{} verify-bytes-negative required_negative_cases contains a non-string id",
                    report_path.display()
                )
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    if required_ids.as_slice() != expected {
        return Err(format!(
            "{} verify-bytes-negative required_negative_cases do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    let negative_cases = report
        .get("negative_cases")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-negative negative_cases is missing",
                report_path.display()
            )
        })?;
    let mut negative_ids = Vec::with_capacity(negative_cases.len());
    for (index, case) in negative_cases.iter().enumerate() {
        let object = case.as_object().ok_or_else(|| {
            format!(
                "{} verify-bytes-negative negative_cases[{index}] is not an object",
                report_path.display()
            )
        })?;
        let id = object
            .get("id")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-negative negative_cases[{index}] missing id",
                    report_path.display()
                )
            })?;
        let category = object
            .get("category")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-negative negative case `{id}` missing category",
                    report_path.display()
                )
            })?;
        if category.trim().is_empty() {
            return Err(format!(
                "{} verify-bytes-negative negative case `{id}` has empty category",
                report_path.display()
            )
            .into());
        }
        if object.get("rejected").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} verify-bytes-negative negative case `{id}` is not proven rejected",
                report_path.display()
            )
            .into());
        }
        let detail = object
            .get("detail")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-negative negative case `{id}` missing detail",
                    report_path.display()
                )
            })?;
        if detail.trim().is_empty() {
            return Err(format!(
                "{} verify-bytes-negative negative case `{id}` has empty detail",
                report_path.display()
            )
            .into());
        }
        if matches!(
            id,
            "plan-static-out-of-bounds-slice"
                | "plan-bytes-get-out-of-bounds"
                | "plan-bytes-set-out-of-bounds"
        ) {
            if object.get("panic_free").and_then(JsonValue::as_bool) != Some(true) {
                return Err(format!(
                    "{} verify-bytes-negative OOB case `{id}` did not prove panic_free=true",
                    report_path.display()
                )
                .into());
            }
            if object.get("failure_kind").and_then(JsonValue::as_str) != Some("structured_error") {
                return Err(format!(
                    "{} verify-bytes-negative OOB case `{id}` did not report a structured_error",
                    report_path.display()
                )
                .into());
            }
        }
        negative_ids.push(id);
    }
    if negative_ids.as_slice() != expected {
        return Err(format!(
            "{} verify-bytes-negative negative_cases ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    let checks = report
        .get("per_step_pass_fail")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-negative per_step_pass_fail is missing",
                report_path.display()
            )
        })?;
    let mut check_ids = Vec::with_capacity(checks.len());
    for (index, check) in checks.iter().enumerate() {
        let object = check.as_object().ok_or_else(|| {
            format!(
                "{} verify-bytes-negative per_step_pass_fail[{index}] is not an object",
                report_path.display()
            )
        })?;
        let id = object
            .get("id")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} verify-bytes-negative per_step_pass_fail[{index}] missing id",
                    report_path.display()
                )
            })?;
        if object.get("pass").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} verify-bytes-negative per_step_pass_fail `{id}` is not passing",
                report_path.display()
            )
            .into());
        }
        check_ids.push(id);
    }
    if check_ids.as_slice() != expected {
        return Err(format!(
            "{} verify-bytes-negative per_step_pass_fail ids do not match the schema contract",
            report_path.display()
        )
        .into());
    }

    Ok(())
}

