fn verify_bytes_release_benchmark_reproduction_report(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    if report.get("measurement_mode").and_then(JsonValue::as_str) != Some("proof") {
        return Err(format!(
            "{} verify-bytes-release-benchmark-reproduction must use measurement_mode=proof",
            report_path.display()
        )
        .into());
    }
    if report.get("reproduction_scope").and_then(JsonValue::as_str)
        != Some("todomvc-release-benchmark-current-slices")
    {
        return Err(format!("{} has invalid reproduction_scope", report_path.display()).into());
    }
    let count = report
        .get("benchmark_report_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing benchmark_report_count", report_path.display()))?;
    if count < 2 {
        return Err(format!(
            "{} benchmark_report_count must be at least 2",
            report_path.display()
        )
        .into());
    }
    let reports = report
        .get("benchmark_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing benchmark_reports", report_path.display()))?;
    if reports.len() != count as usize {
        return Err(format!(
            "{} benchmark_reports length does not match benchmark_report_count",
            report_path.display()
        )
        .into());
    }
    for (index, child) in reports.iter().enumerate() {
        let object = child.as_object().ok_or_else(|| {
            format!(
                "{} benchmark_reports[{index}] is not an object",
                report_path.display()
            )
        })?;
        for key in ["path", "example", "speed_report_path"] {
            if object
                .get(key)
                .and_then(JsonValue::as_str)
                .is_none_or(str::is_empty)
            {
                return Err(format!(
                    "{} benchmark_reports[{index}] missing string `{key}`",
                    report_path.display()
                )
                .into());
            }
        }
        let command = object
            .get("command")
            .and_then(JsonValue::as_str)
            .unwrap_or_default();
        if !matches!(command, "bench-todomvc" | "bench-example") {
            return Err(format!(
                "{} benchmark_reports[{index}] has invalid command `{command}`",
                report_path.display()
            )
            .into());
        }
        if object.get("build_profile").and_then(JsonValue::as_str) != Some("release") {
            return Err(format!(
                "{} benchmark_reports[{index}] was not release evidence",
                report_path.display()
            )
            .into());
        }
        for key in [
            "interaction_latency_ms_p95",
            "runtime_tick_ms_p95",
            "average_ms_per_iteration",
        ] {
            let value = object.get(key).and_then(JsonValue::as_f64);
            if value.is_none_or(|value| !value.is_finite() || value <= 0.0) {
                return Err(format!(
                    "{} benchmark_reports[{index}] missing positive numeric `{key}`",
                    report_path.display()
                )
                .into());
            }
        }
    }
    let max_allowed_ratio = report
        .get("max_allowed_ratio")
        .and_then(JsonValue::as_f64)
        .ok_or_else(|| format!("{} missing max_allowed_ratio", report_path.display()))?;
    if !max_allowed_ratio.is_finite() || max_allowed_ratio < 1.0 {
        return Err(format!(
            "{} max_allowed_ratio must be finite and >= 1.0",
            report_path.display()
        )
        .into());
    }
    let ratios = report
        .get("metric_ratios")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} missing metric_ratios", report_path.display()))?;
    for key in [
        "interaction_latency_ms_p95",
        "runtime_tick_ms_p95",
        "average_ms_per_iteration",
    ] {
        let value = ratios.get(key).and_then(JsonValue::as_f64);
        if value.is_none_or(|value| !value.is_finite() || value < 1.0 || value > max_allowed_ratio)
        {
            return Err(format!(
                "{} metric_ratios.{key} must be within [1.0, max_allowed_ratio]",
                report_path.display()
            )
            .into());
        }
    }
    if report.get("speedup_claim").and_then(JsonValue::as_str) != Some("not_claimed") {
        return Err(format!(
            "{} reproduction report must not claim speedups",
            report_path.display()
        )
        .into());
    }
    if report
        .get("claim_policy")
        .and_then(JsonValue::as_str)
        .is_none_or(str::is_empty)
    {
        return Err(format!("{} missing claim_policy", report_path.display()).into());
    }
    Ok(())
}

fn verify_compiled_artifact_report(report: &JsonValue, path: &Path) -> RuntimeResult<()> {
    for key in [
        "status",
        "report_version",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "generated_at_utc",
        "git_commit",
        "binary_hash",
        "source_path",
        "source_hash",
        "program_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "graph_node_count",
        "semantic_index",
        "compiled_schedule",
        "compiled_artifact",
        "artifact_sections",
        "artifact_sha256s",
    ] {
        if report.get(key).is_none() {
            return Err(format!(
                "{} missing compile-artifact report field `{key}`",
                path.display()
            )
            .into());
        }
    }
    if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
        return Err(format!("{} compile-artifact report did not pass", path.display()).into());
    }
    if report.get("measurement_mode").and_then(JsonValue::as_str) != Some("diagnostic") {
        return Err(format!(
            "{} compile-artifact report measurement_mode must be diagnostic",
            path.display()
        )
        .into());
    }
    let artifact = report
        .get("compiled_artifact")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} compiled_artifact is not an object", path.display()))?;
    for key in [
        "path",
        "sha256",
        "format",
        "artifact_version",
        "program_hash",
        "report_schema_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "capability_summary",
        "machine_plan_verification",
        "source_unit_count",
    ] {
        if artifact.get(key).is_none() {
            return Err(format!("{} compiled_artifact missing `{key}`", path.display()).into());
        }
    }
    if artifact.get("format").and_then(JsonValue::as_str) != Some("boonc-json-v1") {
        return Err(format!("{} compiled_artifact has wrong format", path.display()).into());
    }
    if artifact.get("artifact_version").and_then(JsonValue::as_u64) != Some(1) {
        return Err(format!(
            "{} compiled_artifact has wrong artifact_version",
            path.display()
        )
        .into());
    }
    if artifact.get("program_hash") != report.get("program_hash") {
        return Err(format!(
            "{} compiled_artifact program_hash does not match report",
            path.display()
        )
        .into());
    }
    if artifact.get("machine_plan_hash") != report.get("machine_plan_hash")
        || report.get("machine_plan_hash") != report.get("plan_hash")
    {
        return Err(format!(
            "{} compile-artifact machine_plan_hash, plan_hash, and compiled_artifact.machine_plan_hash must match",
            path.display()
        )
        .into());
    }
    let sections = report
        .get("artifact_sections")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} artifact_sections is not an object", path.display()))?;
    for key in [
        "semantic_index",
        "symbol_table",
        "storage_layout",
        "source_schemas",
        "route_op_streams",
        "dependency_graph",
        "document_lowering_tables",
        "bridge_schemas",
        "compiled_schedule",
        "runtime_plan",
        "machine_plan",
    ] {
        if sections.get(key).and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!("{} artifact_sections `{key}` is not true", path.display()).into());
        }
    }
    verify_artifact_hashes(report, path)?;
    Ok(())
}

fn verify_inspected_compiled_artifact_report(report: &JsonValue, path: &Path) -> RuntimeResult<()> {
    for key in [
        "status",
        "report_version",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "generated_at_utc",
        "git_commit",
        "binary_hash",
        "artifact_path",
        "artifact_hash",
        "program_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "capability_summary",
        "compiled_artifact",
        "artifact_sections",
        "artifact_sha256s",
        "inspection_result",
    ] {
        if report.get(key).is_none() {
            return Err(format!(
                "{} missing inspect-compiled-artifact report field `{key}`",
                path.display()
            )
            .into());
        }
    }
    if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
        return Err(format!(
            "{} inspect-compiled-artifact report did not pass",
            path.display()
        )
        .into());
    }
    if report.get("measurement_mode").and_then(JsonValue::as_str) != Some("diagnostic") {
        return Err(format!(
            "{} inspect-compiled-artifact report measurement_mode must be diagnostic",
            path.display()
        )
        .into());
    }
    let artifact = report
        .get("compiled_artifact")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} compiled_artifact is not an object", path.display()))?;
    for key in [
        "path",
        "sha256",
        "format",
        "artifact_version",
        "program_hash",
        "report_schema_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "capability_summary",
        "machine_plan_verification",
        "source_unit_count",
    ] {
        if artifact.get(key).is_none() {
            return Err(format!("{} compiled_artifact missing `{key}`", path.display()).into());
        }
    }
    if artifact.get("sha256") != report.get("artifact_hash") {
        return Err(format!(
            "{} compiled_artifact sha256 does not match artifact_hash",
            path.display()
        )
        .into());
    }
    if artifact.get("path") != report.get("artifact_path") {
        return Err(format!(
            "{} compiled_artifact path does not match artifact_path",
            path.display()
        )
        .into());
    }
    if artifact.get("program_hash") != report.get("program_hash") {
        return Err(format!(
            "{} compiled_artifact program_hash does not match report",
            path.display()
        )
        .into());
    }
    if artifact.get("machine_plan_hash") != report.get("machine_plan_hash")
        || report.get("machine_plan_hash") != report.get("plan_hash")
    {
        return Err(format!(
            "{} machine_plan_hash, plan_hash, and compiled_artifact.machine_plan_hash must match",
            path.display()
        )
        .into());
    }
    let inspection = report
        .get("inspection_result")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} inspection_result is not an object", path.display()))?;
    for key in [
        "artifact_valid",
        "runtime_engine",
        "plan_executor_runtime_from_artifact",
        "plan_executor_provenance",
        "runtime_instantiated_from_artifact",
        "machine_plan_deserialized_from_artifact",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "machine_plan_verification",
        "runtime_plan_present",
        "runtime_plan_generic_derived_deserialized_from_artifact",
        "runtime_plan_generic_derived_deserialized_counts",
        "runtime_plan_storage_deserialized_from_artifact",
        "runtime_plan_storage_deserialized_counts",
        "runtime_plan_document_lowering_deserialized_from_artifact",
        "runtime_plan_document_lowering_deserialized_counts",
        "runtime_plan_non_route_tables_deserialized_from_artifact",
        "runtime_plan_non_route_tables_deserialized_counts",
        "runtime_plan_source_routes_deserialized_from_artifact",
        "runtime_plan_source_routes_deserialized_counts",
        "source_free_runtime_load_available",
        "source_reparse_required_for_current_runtime",
        "source_reparse_attempted",
        "source_file_access",
        "parser_ast_required_for_execution",
        "typed_ir_required_for_mvp_loader",
        "scenario_execution_available",
        "blocked_task",
        "scenario_execution_pending_task",
        "missing_runtime_plan_sections",
    ] {
        if inspection.get(key).is_none() {
            return Err(format!("{} inspection_result missing `{key}`", path.display()).into());
        }
    }
    if inspection
        .get("artifact_valid")
        .and_then(JsonValue::as_bool)
        != Some(true)
        || inspection
            .get("plan_executor_runtime_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("machine_plan_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection.get("runtime_engine").and_then(JsonValue::as_str) != Some("plan_executor")
        || inspection
            .get("runtime_instantiated_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("source_free_runtime_load_available")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("runtime_plan_generic_derived_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("runtime_plan_storage_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("runtime_plan_document_lowering_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("runtime_plan_non_route_tables_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("runtime_plan_source_routes_deserialized_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || inspection
            .get("source_reparse_required_for_current_runtime")
            .and_then(JsonValue::as_bool)
            != Some(false)
        || inspection
            .get("typed_ir_required_for_mvp_loader")
            .and_then(JsonValue::as_bool)
            != Some(false)
        || inspection
            .get("source_reparse_attempted")
            .and_then(JsonValue::as_bool)
            != Some(false)
        || inspection
            .get("source_file_access")
            .and_then(JsonValue::as_str)
            != Some("not_attempted")
        || inspection
            .get("scenario_execution_available")
            .and_then(JsonValue::as_bool)
            != Some(false)
    {
        return Err(format!(
            "{} inspection_result must prove source-free PlanExecutor load and must not claim scenario execution",
            path.display()
        )
        .into());
    }
    let provenance = inspection
        .get("plan_executor_provenance")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} plan_executor_provenance is not an object",
                path.display()
            )
        })?;
    if provenance.get("engine").and_then(JsonValue::as_str) != Some("plan_executor")
        || provenance
            .get("generic_fallback_enabled")
            .and_then(JsonValue::as_bool)
            != Some(false)
    {
        return Err(format!(
            "{} inspection_result must prove PlanExecutor provenance with no generic fallback",
            path.display()
        )
        .into());
    }
    let generic_counts = inspection
        .get("runtime_plan_generic_derived_deserialized_counts")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} inspection_result runtime_plan_generic_derived_deserialized_counts is not an object",
                path.display()
            )
        })?;
    for key in [
        "function_count",
        "root_supported_count",
        "indexed_supported_count",
        "unsupported_reason_count",
    ] {
        if generic_counts
            .get(key)
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} inspection_result runtime_plan_generic_derived_deserialized_counts missing `{key}`",
                path.display()
            )
            .into());
        }
    }
    let storage_counts = inspection
        .get("runtime_plan_storage_deserialized_counts")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} inspection_result runtime_plan_storage_deserialized_counts is not an object",
                path.display()
            )
        })?;
    for key in [
        "root_slot_count",
        "root_initial_field_copy_count",
        "list_slot_count",
        "indexed_row_initial_reset_count",
        "initial_row_count",
    ] {
        if storage_counts
            .get(key)
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} inspection_result runtime_plan_storage_deserialized_counts missing `{key}`",
                path.display()
            )
            .into());
        }
    }
    let document_counts = inspection
        .get("runtime_plan_document_lowering_deserialized_counts")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} inspection_result runtime_plan_document_lowering_deserialized_counts is not an object",
                path.display()
            )
        })?;
    for key in [
        "root_summary_path_count",
        "list_summary_field_count",
        "dynamic_list_view_list_count",
        "projection_storage_resolution_count",
        "unresolved_projection_storage_path_count",
        "observed_root_path_count",
        "render_slot_count",
        "render_slot_failure_count",
    ] {
        if document_counts
            .get(key)
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} inspection_result runtime_plan_document_lowering_deserialized_counts missing `{key}`",
                path.display()
            )
            .into());
        }
    }
    let non_route_counts = inspection
        .get("runtime_plan_non_route_tables_deserialized_counts")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} inspection_result runtime_plan_non_route_tables_deserialized_counts is not an object",
                path.display()
            )
        })?;
    for key in [
        "runtime_symbol_count",
        "scalar_source_path_count",
        "scalar_branch_count",
        "derived_text_transform_count",
        "list_operation_count",
        "list_projection_count",
        "list_source_binding_count",
    ] {
        if non_route_counts
            .get(key)
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} inspection_result runtime_plan_non_route_tables_deserialized_counts missing `{key}`",
                path.display()
            )
            .into());
        }
    }
    let source_route_counts = inspection
        .get("runtime_plan_source_routes_deserialized_counts")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} inspection_result runtime_plan_source_routes_deserialized_counts is not an object",
                path.display()
            )
        })?;
    for key in [
        "route_count",
        "id_slot_count",
        "label_slot_count",
        "routes_with_ids",
        "action_table_slot_count",
        "action_op_stream_count",
        "total_action_op_count",
        "max_action_op_count",
        "source_payload_schema_count",
        "source_payload_field_count",
        "source_payload_text_field_count",
        "source_payload_key_field_count",
        "source_payload_address_field_count",
        "source_payload_bytes_field_count",
        "source_payload_pointer_field_count",
    ] {
        if source_route_counts
            .get(key)
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} inspection_result runtime_plan_source_routes_deserialized_counts missing `{key}`",
                path.display()
            )
            .into());
        }
    }
    if inspection
        .get("parser_ast_required_for_execution")
        .and_then(JsonValue::as_bool)
        != Some(false)
    {
        return Err(format!(
            "{} inspection_result must not require parser AST",
            path.display()
        )
        .into());
    }
    let missing_runtime_plan_sections = inspection
        .get("missing_runtime_plan_sections")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} inspection_result missing_runtime_plan_sections is not an array",
                path.display()
            )
        })?;
    if !missing_runtime_plan_sections.is_empty() {
        return Err(format!(
            "{} inspection_result must not list missing runtime plan sections",
            path.display()
        )
        .into());
    }
    verify_compiled_artifact_sections(report, path)?;
    verify_artifact_hashes(report, path)?;
    Ok(())
}

fn verify_compiled_artifact_scenario_report(report: &JsonValue, path: &Path) -> RuntimeResult<()> {
    for key in [
        "status",
        "report_version",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "generated_at_utc",
        "git_commit",
        "binary_hash",
        "source_path",
        "source_hash",
        "scenario_path",
        "scenario_hash",
        "program_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "artifact_path",
        "artifact_hash",
        "compiled_artifact",
        "artifact_sections",
        "artifact_sha256s",
        "artifact_scenario",
    ] {
        if report.get(key).is_none() {
            return Err(format!(
                "{} missing verify-compiled-artifact-scenario report field `{key}`",
                path.display()
            )
            .into());
        }
    }
    if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
        return Err(format!(
            "{} verify-compiled-artifact-scenario report did not pass",
            path.display()
        )
        .into());
    }
    if report.get("measurement_mode").and_then(JsonValue::as_str) != Some("proof") {
        return Err(format!(
            "{} verify-compiled-artifact-scenario report measurement_mode must be proof",
            path.display()
        )
        .into());
    }
    let artifact = report
        .get("compiled_artifact")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} compiled_artifact is not an object", path.display()))?;
    for key in [
        "path",
        "sha256",
        "format",
        "artifact_version",
        "program_hash",
        "report_schema_hash",
        "machine_plan_hash",
        "plan_hash",
        "target_profile",
        "capability_summary",
        "machine_plan_verification",
        "source_unit_count",
    ] {
        if artifact.get(key).is_none() {
            return Err(format!("{} compiled_artifact missing `{key}`", path.display()).into());
        }
    }
    if artifact.get("sha256") != report.get("artifact_hash") {
        return Err(format!(
            "{} compiled_artifact sha256 does not match artifact_hash",
            path.display()
        )
        .into());
    }
    if artifact.get("path") != report.get("artifact_path") {
        return Err(format!(
            "{} compiled_artifact path does not match artifact_path",
            path.display()
        )
        .into());
    }
    if artifact.get("program_hash") != report.get("program_hash") {
        return Err(format!(
            "{} compiled_artifact program_hash does not match report",
            path.display()
        )
        .into());
    }
    if artifact.get("machine_plan_hash") != report.get("machine_plan_hash")
        || report.get("machine_plan_hash") != report.get("plan_hash")
    {
        return Err(format!(
            "{} machine_plan_hash, plan_hash, and compiled_artifact.machine_plan_hash must match",
            path.display()
        )
        .into());
    }
    let scenario = report
        .get("artifact_scenario")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} artifact_scenario is not an object", path.display()))?;
    for key in [
        "scenario_execution_available",
        "scenario_execution_from_artifact",
        "runtime_instantiated_from_artifact",
        "source_reparse_attempted",
        "source_file_access",
        "typed_ir_required_for_artifact_execution",
        "parser_ast_required_for_artifact_execution",
        "source_oracle_layer",
        "runtime_engine",
        "generic_fallback_enabled",
        "render_patch_surface",
        "semantic_deltas_match",
        "render_patches_match",
        "state_summary_match",
        "parity_passed",
        "source_signature_hash",
        "artifact_signature_hash",
    ] {
        if scenario.get(key).is_none() {
            return Err(format!("{} artifact_scenario missing `{key}`", path.display()).into());
        }
    }
    if scenario
        .get("scenario_execution_available")
        .and_then(JsonValue::as_bool)
        != Some(true)
        || scenario
            .get("scenario_execution_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || scenario
            .get("runtime_instantiated_from_artifact")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || scenario
            .get("source_oracle_layer")
            .and_then(JsonValue::as_str)
            != Some("plan_executor")
        || scenario.get("runtime_engine").and_then(JsonValue::as_str) != Some("plan_executor")
        || scenario
            .get("generic_fallback_enabled")
            .and_then(JsonValue::as_bool)
            != Some(false)
        || scenario
            .get("render_patch_surface")
            .and_then(JsonValue::as_str)
            != Some("not_owned_by_plan_executor")
        || scenario
            .get("semantic_deltas_match")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || scenario
            .get("render_patches_match")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || scenario
            .get("state_summary_match")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || scenario.get("parity_passed").and_then(JsonValue::as_bool) != Some(true)
    {
        return Err(format!(
            "{} artifact_scenario must prove artifact execution and source parity",
            path.display()
        )
        .into());
    }
    if scenario
        .get("source_reparse_attempted")
        .and_then(JsonValue::as_bool)
        != Some(false)
        || scenario
            .get("source_file_access")
            .and_then(JsonValue::as_str)
            != Some("not_attempted")
        || scenario
            .get("typed_ir_required_for_artifact_execution")
            .and_then(JsonValue::as_bool)
            != Some(false)
        || scenario
            .get("parser_ast_required_for_artifact_execution")
            .and_then(JsonValue::as_bool)
            != Some(false)
    {
        return Err(format!(
            "{} artifact_scenario must be source-free and AST-free",
            path.display()
        )
        .into());
    }
    if scenario
        .get("source_signature_hash")
        .and_then(JsonValue::as_str)
        != scenario
            .get("artifact_signature_hash")
            .and_then(JsonValue::as_str)
    {
        return Err(format!(
            "{} artifact_scenario source/artifact signature hashes differ",
            path.display()
        )
        .into());
    }
    verify_report_file_hash(report, path, "source_path", "source_hash")?;
    verify_report_file_hash(report, path, "scenario_path", "scenario_hash")?;
    verify_compiled_artifact_sections(report, path)?;
    verify_artifact_hashes(report, path)?;
    Ok(())
}

fn verify_bytecode_report(report: &JsonValue, path: &Path) -> RuntimeResult<()> {
    for key in [
        "status",
        "report_version",
        "command",
        "command_argv",
        "measurement_mode",
        "exit_status",
        "generated_at_utc",
        "git_commit",
        "binary_hash",
        "source_path",
        "source_hash",
        "scenario_path",
        "scenario_hash",
        "program_hash",
        "graph_node_count",
        "semantic_index",
        "compiled_schedule",
        "per_step_pass_fail",
        "artifact_sha256s",
        "expression_bytecode",
    ] {
        if report.get(key).is_none() {
            return Err(format!(
                "{} missing verify-bytecode report field `{key}`",
                path.display()
            )
            .into());
        }
    }
    if report.get("status").and_then(JsonValue::as_str) != Some("pass") {
        return Err(format!("{} verify-bytecode report did not pass", path.display()).into());
    }
    if report.get("measurement_mode").and_then(JsonValue::as_str) != Some("proof") {
        return Err(format!(
            "{} verify-bytecode report measurement_mode must be proof",
            path.display()
        )
        .into());
    }
    verify_common_report_shape(report, path)?;
    verify_measurement_mode(report, path)?;
    verify_report_file_hash(report, path, "source_path", "source_hash")?;
    verify_report_file_hash(report, path, "scenario_path", "scenario_hash")?;
    verify_artifact_hashes(report, path)?;

    let bytecode = report
        .get("expression_bytecode")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} expression_bytecode is not an object", path.display()))?;
    for key in [
        "version",
        "execution_surface",
        "interpreter_oracle",
        "candidate_expression_count",
        "compiled_expression_count",
        "parity_sample_count",
        "parity_passed",
        "fallback_count",
        "fallback_reasons",
        "deopt_count",
        "deopt_reasons",
        "op_histogram",
        "warm_path_allocation_count",
        "hot_path_ready",
        "samples",
    ] {
        if bytecode.get(key).is_none() {
            return Err(format!("{} expression_bytecode missing `{key}`", path.display()).into());
        }
    }
    if bytecode.get("version").and_then(JsonValue::as_u64) != Some(1) {
        return Err(format!("{} expression_bytecode has wrong version", path.display()).into());
    }
    let compiled_count = bytecode
        .get("compiled_expression_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} expression_bytecode compiled_expression_count is not numeric",
                path.display()
            )
        })?;
    let sample_count = bytecode
        .get("parity_sample_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} expression_bytecode parity_sample_count is not numeric",
                path.display()
            )
        })?;
    if compiled_count == 0 || sample_count < compiled_count {
        return Err(format!(
            "{} expression_bytecode must compile and sample at least one expression",
            path.display()
        )
        .into());
    }
    if bytecode.get("parity_passed").and_then(JsonValue::as_bool) != Some(true) {
        return Err(format!("{} expression_bytecode parity did not pass", path.display()).into());
    }
    let fallback_count = bytecode
        .get("fallback_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} expression_bytecode fallback_count is not numeric",
                path.display()
            )
        })?;
    let deopt_count = bytecode
        .get("deopt_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} expression_bytecode deopt_count is not numeric",
                path.display()
            )
        })?;
    if deopt_count != 0 {
        return Err(format!(
            "{} expression_bytecode deopt_count is nonzero",
            path.display()
        )
        .into());
    }
    if bytecode
        .get("fallback_reasons")
        .and_then(JsonValue::as_array)
        .is_none()
        || bytecode
            .get("deopt_reasons")
            .and_then(JsonValue::as_array)
            .is_none()
    {
        return Err(format!(
            "{} expression_bytecode fallback/deopt reasons must be arrays",
            path.display()
        )
        .into());
    }
    let op_histogram = bytecode
        .get("op_histogram")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} expression_bytecode op_histogram is not an object",
                path.display()
            )
        })?;
    if op_histogram.is_empty()
        || op_histogram
            .values()
            .any(|value| value.as_u64().unwrap_or_default() == 0)
    {
        return Err(format!(
            "{} expression_bytecode op_histogram must contain nonzero op counts",
            path.display()
        )
        .into());
    }
    if bytecode
        .get("warm_path_allocation_count")
        .and_then(JsonValue::as_u64)
        .is_none()
    {
        return Err(format!(
            "{} expression_bytecode warm_path_allocation_count is not numeric",
            path.display()
        )
        .into());
    }
    if bytecode.get("hot_path_ready").and_then(JsonValue::as_bool) == Some(true)
        && (fallback_count != 0 || deopt_count != 0)
    {
        return Err(format!(
            "{} expression_bytecode cannot claim hot_path_ready with fallback/deopt activity",
            path.display()
        )
        .into());
    }
    Ok(())
}

fn verify_compiled_artifact_sections(report: &JsonValue, path: &Path) -> RuntimeResult<()> {
    let sections = report
        .get("artifact_sections")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} artifact_sections is not an object", path.display()))?;
    for key in [
        "semantic_index",
        "symbol_table",
        "storage_layout",
        "source_schemas",
        "route_op_streams",
        "dependency_graph",
        "document_lowering_tables",
        "bridge_schemas",
        "compiled_schedule",
        "runtime_plan",
        "machine_plan",
    ] {
        if sections.get(key).and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!("{} artifact_sections `{key}` is not true", path.display()).into());
        }
    }
    Ok(())
}

fn verify_compiler_boundaries_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let status = report.get("status").and_then(JsonValue::as_str);
    if status == Some("fail") {
        verify_failing_blocker_report_shape(report, report_path)?;
    } else if status == Some("pass") {
        verify_common_report_shape(report, report_path)?;
    } else if status != Some("pass") {
        return Err(format!(
            "{} verify-compiler-boundaries status must be pass or fail",
            report_path.display()
        )
        .into());
    }

    let contract = report
        .get("compiler_boundary_contract")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} missing compiler_boundary_contract",
                report_path.display()
            )
        })?;
    if !contract.contains("compiler/runtime boundary") {
        return Err(format!(
            "{} compiler_boundary_contract does not name compiler/runtime boundary extraction",
            report_path.display()
        )
        .into());
    }

    let boundary_status = report
        .get("compiler_boundary_status")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing compiler_boundary_status", report_path.display()))?;
    if !matches!(boundary_status, "partial" | "complete") {
        return Err(format!(
            "{} compiler_boundary_status must be partial or complete",
            report_path.display()
        )
        .into());
    }

    for key in [
        "boon_compiler",
        "boon_plan_executor",
        "boundary_decomposition",
        "dependency_direction",
        "acceptance",
    ] {
        if report.get(key).and_then(JsonValue::as_object).is_none() {
            return Err(format!("{} missing object `{key}`", report_path.display()).into());
        }
    }

    let compiler = report
        .get("boon_compiler")
        .and_then(JsonValue::as_object)
        .unwrap();
    for key in [
        "crate_present",
        "workspace_member",
        "workspace_dependency",
        "facade_exports_compile_typed_program",
        "facade_delegates_to_plan_backend",
        "compiler_owns_machine_plan_backend_source",
    ] {
        if compiler.get(key).and_then(JsonValue::as_bool).is_none() {
            return Err(format!(
                "{} boon_compiler.{key} must be boolean",
                report_path.display()
            )
            .into());
        }
    }

    let plan_executor = report
        .get("boon_plan_executor")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} missing boon_plan_executor object",
                report_path.display()
            )
        })?;
    for key in [
        "crate_present",
        "workspace_member",
        "workspace_dependency",
        "depends_on_boon_plan",
        "initial_state_executor_extracted",
        "source_route_selection_extracted",
        "source_route_json_execution_extracted",
        "root_source_event_work_selection_extracted",
        "root_json_update_evaluator_extracted",
        "root_json_update_execution_extracted",
        "root_runtime_branch_update_execution_extracted",
        "root_bytes_update_dispatch_extracted",
        "root_bytes_shadowed_runtime_arms_removed",
        "root_bytes_runtime_environment_wrapped",
        "root_bytes_environment_capability_extracted",
        "root_json_state_write_extracted",
        "root_bytes_source_payload_report_extracted",
        "root_bytes_initial_storage_extracted",
        "root_bytes_read_evaluator_extracted",
        "root_bytes_write_evaluator_extracted",
        "root_bytes_source_payload_commit_extracted",
        "root_bytes_state_transition_extracted",
        "root_bytes_state_owner_capability_extracted",
        "initial_list_row_value_conversion_extracted",
        "indexed_fixed_byte_bank_lookup_extracted",
        "indexed_update_batch_execution_extracted",
        "indexed_json_update_evaluator_extracted",
        "list_mutation_records_extracted",
        "list_append_row_construction_extracted",
        "list_append_execution_extracted",
        "list_remove_execution_extracted",
        "list_row_default_fields_extracted",
        "list_row_report_fields_extracted",
        "list_row_state_carrier_extracted",
        "list_row_initial_refresh_extracted",
        "list_row_bool_not_refresh_extracted",
        "list_row_expression_refresh_extracted",
        "list_row_textlike_field_extracted",
        "assertion_checkpoint_extracted",
        "root_update_candidate_tracker_extracted",
        "root_update_commit_assembly_extracted",
        "root_update_commit_batch_extracted",
        "root_update_storage_transition_extracted",
        "root_update_state_owner_capability_extracted",
        "runtime_root_state_container_wrapped",
        "runtime_plan_executor_root_state_carried",
        "root_state_update_helpers_extracted",
        "root_executed_update_state_application_extracted",
        "root_update_branch_collection_extracted",
        "root_state_container_extracted",
        "source_payload_bytes_key_policy_extracted",
        "live_source_event_expectation_matcher_extracted",
        "live_source_event_expected_toml_builder_extracted",
        "source_route_command_output_extracted",
        "root_scenario_command_output_extracted",
        "scenario_events_command_output_extracted",
        "source_event_payload_bytes_artifact_report_extracted",
        "source_route_orchestration_extracted",
        "source_route_runtime_callback_removed",
        "root_scenario_step_preparation_extracted",
        "source_derived_step_delta_bundle_extracted",
    ] {
        if plan_executor
            .get(key)
            .and_then(JsonValue::as_bool)
            .is_none()
        {
            return Err(format!(
                "{} boon_plan_executor.{key} must be boolean",
                report_path.display()
            )
            .into());
        }
    }
    if plan_executor
        .get("frontend_dependency_count")
        .and_then(JsonValue::as_u64)
        .is_none()
    {
        return Err(format!(
            "{} boon_plan_executor.frontend_dependency_count must be a count",
            report_path.display()
        )
        .into());
    }

    let decomposition = report
        .get("boundary_decomposition")
        .and_then(JsonValue::as_object)
        .unwrap();
    for key in [
        "lowering_still_owned_by_plan_backend",
        "plan_schema_still_uses_ir_ids",
        "plan_schema_still_uses_ir_source_schema",
        "boon_plan_frontend_dependencies_optional_only",
        "boon_plan_old_ir_adapter_feature_present",
        "boon_plan_old_backend_feature_present",
        "boon_compiler_enables_old_backend_feature",
        "boon_compiler_enables_old_ir_adapter_feature",
        "boon_plan_default_build_schema_only",
        "parser_ast_still_in_plan_lowering",
        "plan_executor_core_still_frontend_coupled",
        "runtime_frontend_orchestration_remaining",
        "runtime_document_list_metadata_extracted",
        "runtime_document_observed_root_paths_extracted",
        "runtime_document_projection_storage_resolutions_extracted",
        "runtime_document_render_slots_extracted",
        "runtime_list_operations_extracted",
        "runtime_list_projection_dtos_extracted",
        "runtime_list_source_bindings_extracted",
        "runtime_parser_dependency_removed",
        "runtime_public_load_and_lower_removed",
        "runtime_public_parsed_project_cache_removed",
        "runtime_root_scenario_orchestration_remaining",
        "runtime_root_state_paths_extracted",
        "runtime_source_payload_counts_extracted",
        "runtime_symbols_extracted",
        "runtime_field_slot_collision_diagnostics_extracted",
        "runtime_scalar_equations_extracted",
        "runtime_profile_metadata_extracted",
        "runtime_unsupported_diagnostics_extracted",
        "runtime_generic_derived_plan_inventory_extracted",
        "runtime_generic_derived_runtime_plan_inventory_extracted",
        "runtime_generic_derived_ast_lowering_extracted",
        "runtime_derived_equation_plan_extracted",
        "runtime_update_expression_dtos_extracted",
        "runtime_bytes_scalar_arg_dtos_extracted",
        "runtime_derived_value_kind_dtos_extracted",
        "runtime_raw_ir_value_enum_imports_qualified",
        "runtime_row_template_initial_values_ir_free",
        "runtime_ir_debug_tables_delegated_to_compiler",
        "runtime_typecheck_report_metadata_delegated_to_compiler",
        "runtime_typed_program_report_metadata_delegated_to_compiler",
        "runtime_typed_program_inventory_counts_delegated_to_compiler",
        "runtime_dead_ir_document_metadata_helpers_removed",
        "runtime_source_route_bool_facts_extracted",
        "runtime_source_route_root_targets_extracted",
        "runtime_source_route_root_text_transforms_extracted",
        "runtime_source_route_router_targets_extracted",
        "runtime_source_route_sources_extracted",
        "runtime_source_route_command_adapter_remaining",
        "runtime_static_analysis_dtos_extracted",
        "runtime_storage_indexed_derived_fields_extracted",
        "runtime_storage_initialization_ir_free",
        "runtime_legacy_storage_constructor_uses_compiler_plan",
        "runtime_storage_initial_rows_extracted",
        "runtime_storage_indexed_row_initial_resets_extracted",
        "runtime_storage_list_slots_metadata_extracted",
        "runtime_storage_row_templates_extracted",
        "runtime_storage_root_slots_extracted",
        "runtime_typed_storage_layout_counts_extracted",
        "runtime_typecheck_dependency_removed",
    ] {
        if decomposition
            .get(key)
            .and_then(JsonValue::as_bool)
            .is_none()
        {
            return Err(format!(
                "{} boundary_decomposition.{key} must be boolean",
                report_path.display()
            )
            .into());
        }
    }
    let next_cuts = decomposition
        .get("next_architectural_cuts")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} boundary_decomposition.next_architectural_cuts must be an array",
                report_path.display()
            )
        })?;
    if next_cuts.is_empty() || !next_cuts.iter().all(|item| item.as_str().is_some()) {
        return Err(format!(
            "{} boundary_decomposition.next_architectural_cuts must contain strings",
            report_path.display()
        )
        .into());
    }

    let direction = report
        .get("dependency_direction")
        .and_then(JsonValue::as_object)
        .unwrap();
    for key in [
        "external_direct_plan_compile_call_count",
        "facade_call_site_count",
    ] {
        if direction.get(key).and_then(JsonValue::as_u64).is_none() {
            return Err(format!(
                "{} dependency_direction.{key} must be a count",
                report_path.display()
            )
            .into());
        }
    }
    for key in [
        "external_direct_plan_compile_calls",
        "facade_call_sites",
        "boon_plan_executor_frontend_dependencies",
        "boon_runtime_frontend_dependencies",
    ] {
        if direction.get(key).and_then(JsonValue::as_array).is_none() {
            return Err(format!(
                "{} dependency_direction.{key} must be an array",
                report_path.display()
            )
            .into());
        }
    }
    for key in [
        "boon_plan_depends_on_boon_ir",
        "boon_plan_optionally_depends_on_boon_ir",
        "boon_plan_depends_on_boon_parser",
        "boon_plan_optionally_depends_on_boon_parser",
        "boon_plan_optionally_depends_on_boon_typecheck",
        "boon_plan_old_ir_adapter_feature_present",
        "boon_plan_imports_parser_ast",
    ] {
        if direction.get(key).and_then(JsonValue::as_bool).is_none() {
            return Err(format!(
                "{} dependency_direction.{key} must be boolean",
                report_path.display()
            )
            .into());
        }
    }

    let acceptance = report
        .get("acceptance")
        .and_then(JsonValue::as_object)
        .unwrap();
    let full = acceptance
        .get("full_milestone_complete")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| {
            format!(
                "{} acceptance.full_milestone_complete must be boolean",
                report_path.display()
            )
        })?;
    let codegen_allowed = acceptance
        .get("rust_zig_codegen_allowed")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| {
            format!(
                "{} acceptance.rust_zig_codegen_allowed must be boolean",
                report_path.display()
            )
        })?;
    if codegen_allowed != full {
        return Err(format!(
            "{} rust_zig_codegen_allowed must match full_milestone_complete",
            report_path.display()
        )
        .into());
    }
    if status == Some("pass") && (!full || boundary_status != "complete") {
        return Err(format!(
            "{} passing compiler-boundary report must mark full milestone complete",
            report_path.display()
        )
        .into());
    }
    if status == Some("fail") && full {
        return Err(format!(
            "{} failing compiler-boundary report cannot mark full milestone complete",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

