fn verify_bytes_machine_plan_all_report(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    if report.get("aggregate_scope").and_then(JsonValue::as_str)
        != Some("bytes-machine-plan-current-slices")
    {
        return Err(format!(
            "{} has invalid aggregate_scope for BYTES/MachinePlan aggregate",
            report_path.display()
        )
        .into());
    }
    if report.get("check_existing").and_then(JsonValue::as_bool) != Some(true) {
        return Err(format!(
            "{} BYTES/MachinePlan aggregate did not run with --check-existing",
            report_path.display()
        )
        .into());
    }
    if report
        .get("aggregate_checks_pass")
        .and_then(JsonValue::as_bool)
        != Some(true)
    {
        return Err(format!(
            "{} BYTES/MachinePlan aggregate did not record passing checks",
            report_path.display()
        )
        .into());
    }
    let expected_children = expected_bytes_machine_plan_child_reports();
    let aggregate_git_commit = report
        .get("git_commit")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing git_commit", report_path.display()))?;
    let aggregate_worktree_fingerprint = report
        .get("worktree_fingerprint")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing worktree_fingerprint", report_path.display()))?;
    let aggregate_worktree_fingerprint_scope = report
        .get("worktree_fingerprint_scope")
        .and_then(JsonValue::as_str);
    let required_count = report
        .get("required_report_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing required_report_count", report_path.display()))?;
    let checked_count = report
        .get("checked_report_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing checked_report_count", report_path.display()))?;
    if required_count != expected_children.len() as u64 || checked_count != required_count {
        return Err(format!(
            "{} checked_report_count {checked_count} does not match required_report_count {required_count}",
            report_path.display()
        )
        .into());
    }
    let child_reports = report
        .get("child_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing child_reports", report_path.display()))?;
    if child_reports.len() as u64 != required_count {
        return Err(format!(
            "{} child_reports length {} does not match required_report_count {required_count}",
            report_path.display(),
            child_reports.len()
        )
        .into());
    }
    let artifacts = report
        .get("artifact_sha256s")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing artifact_sha256s", report_path.display()))?;
    let mut artifact_hashes_by_path = BTreeMap::new();
    for artifact in artifacts {
        let path = artifact
            .get("path")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} aggregate artifact entry missing path",
                    report_path.display()
                )
            })?;
        let sha256 = artifact
            .get("sha256")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} aggregate artifact entry `{path}` missing sha256",
                    report_path.display()
                )
            })?;
        artifact_hashes_by_path.insert(path, sha256);
    }
    let mut labels = BTreeSet::new();
    let mut proof_count = 0u64;
    let mut diagnostic_count = 0u64;
    for (index, child) in child_reports.iter().enumerate() {
        let label = child
            .get("label")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child_reports[{index}] missing label",
                    report_path.display()
                )
            })?;
        if !labels.insert(label.to_owned()) {
            return Err(format!(
                "{} duplicate child report label `{label}`",
                report_path.display()
            )
            .into());
        }
        let expected_child = expected_children
            .iter()
            .find(|expected| expected.label == label)
            .ok_or_else(|| {
                format!(
                    "{} unexpected child report label `{label}`",
                    report_path.display()
                )
            })?;
        let path = child
            .get("path")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child_reports[{index}] missing path",
                    report_path.display()
                )
            })?;
        if path != expected_child.path {
            return Err(format!(
                "{} child report `{label}` path `{path}` does not match expected `{}`",
                report_path.display(),
                expected_child.path
            )
            .into());
        }
        let sha256 = child
            .get("sha256")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child_reports[{index}] missing sha256",
                    report_path.display()
                )
            })?;
        if !is_sha256_hex(sha256) {
            return Err(format!(
                "{} child report `{label}` has non-SHA256 hash `{sha256}`",
                report_path.display()
            )
            .into());
        }
        if child.get("status").and_then(JsonValue::as_str) != Some("pass") {
            return Err(format!(
                "{} child report `{label}` did not pass",
                report_path.display()
            )
            .into());
        }
        if child.get("command").and_then(JsonValue::as_str) != Some(expected_child.command) {
            return Err(format!(
                "{} child report `{label}` command does not match expected `{}`",
                report_path.display(),
                expected_child.command
            )
            .into());
        }
        let command_argv = child
            .get("command_argv")
            .and_then(JsonValue::as_array)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` missing command_argv",
                    report_path.display()
                )
            })?;
        if command_argv.is_empty() || command_argv.iter().any(|arg| arg.as_str().is_none()) {
            return Err(format!(
                "{} child report `{label}` command_argv is empty or malformed",
                report_path.display()
            )
            .into());
        }
        if label != "phase0-baseline"
            && !child_command_argv_proves_expected_command(command_argv, expected_child.command)
        {
            return Err(format!(
                "{} child report `{label}` command_argv does not contain expected command `{}`",
                report_path.display(),
                expected_child.command
            )
            .into());
        }
        if let Some(report_arg) = command_argv_value_after(command_argv, "--report")
            && report_arg != path
        {
            return Err(format!(
                "{} child report `{label}` command_argv --report `{report_arg}` does not match child path `{path}`",
                report_path.display()
            )
            .into());
        }
        let mode = child
            .get("measurement_mode")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` missing measurement_mode",
                    report_path.display()
                )
            })?;
        if mode != expected_child.measurement_mode {
            return Err(format!(
                "{} child report `{label}` measurement_mode `{mode}` does not match expected `{}`",
                report_path.display(),
                expected_child.measurement_mode
            )
            .into());
        }
        match mode {
            "proof" => proof_count += 1,
            "diagnostic" => diagnostic_count += 1,
            other => {
                return Err(format!(
                    "{} child report `{label}` has invalid measurement_mode `{other}`",
                    report_path.display()
                )
                .into());
            }
        }
        let child_git_commit = child
            .get("git_commit")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` missing `git_commit`",
                    report_path.display()
                )
            })?;
        let child_uses_source_replay_scope = expected_child.command == "run-plan-scenario-events"
            && child
                .get("source_replay_identity_required")
                .and_then(JsonValue::as_bool)
                == Some(true)
            && child
                .get("source_replay_identity_present")
                .and_then(JsonValue::as_bool)
                == Some(true)
            && child
                .get("source_replay_identity_fresh")
                .and_then(JsonValue::as_bool)
                == Some(true)
            && child
                .get("worktree_fingerprint_basis")
                .and_then(JsonValue::as_str)
                == Some("scoped")
            && child
                .get("worktree_fingerprint_scope")
                .and_then(JsonValue::as_str)
                == Some("plan-executor-source-replay")
            && child.get("worktree_fresh").and_then(JsonValue::as_bool) == Some(true);
        if label != "phase0-baseline"
            && child_git_commit != aggregate_git_commit
            && !child_uses_source_replay_scope
        {
            return Err(format!(
                "{} child report `{label}` git_commit `{child_git_commit}` does not match aggregate `{aggregate_git_commit}`",
                report_path.display()
            )
            .into());
        }
        if label != "phase0-baseline" {
            let child_worktree_fingerprint = child
                .get("worktree_fingerprint")
                .and_then(JsonValue::as_str)
                .ok_or_else(|| {
                    format!(
                        "{} child report `{label}` missing `worktree_fingerprint`",
                        report_path.display()
                    )
                })?;
            let child_uses_matching_scoped_freshness = child
                .get("worktree_fingerprint_basis")
                .and_then(JsonValue::as_str)
                == Some("scoped")
                && child
                    .get("worktree_fingerprint_scope")
                    .and_then(JsonValue::as_str)
                    == aggregate_worktree_fingerprint_scope
                && child.get("worktree_fresh").and_then(JsonValue::as_bool) == Some(true);
            if child_worktree_fingerprint != aggregate_worktree_fingerprint
                && !child_uses_source_replay_scope
                && !child_uses_matching_scoped_freshness
            {
                return Err(format!(
                    "{} child report `{label}` worktree_fingerprint `{child_worktree_fingerprint}` does not match aggregate `{aggregate_worktree_fingerprint}`",
                    report_path.display()
                )
                .into());
            }
        }
        if label != "phase0-baseline"
            && child.get("worktree_fresh").and_then(JsonValue::as_bool) != Some(true)
        {
            return Err(format!(
                "{} child report `{label}` was not generated for the aggregate worktree fingerprint",
                report_path.display()
            )
            .into());
        }
        if child.get("schema_valid").and_then(JsonValue::as_bool) != Some(true) {
            return Err(format!(
                "{} child report `{label}` was not schema-valid",
                report_path.display()
            )
            .into());
        }
        if child
            .get("artifact_hashes_fresh")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} child report `{label}` had stale artifact hashes",
                report_path.display()
            )
            .into());
        }
        verify_child_expression_kind_coverage(child, label, report_path)?;
        verify_child_source_payload_typing_summary(child, label, report_path)?;
        let Some(bound_sha256) = artifact_hashes_by_path.get(path) else {
            return Err(format!(
                "{} child report `{label}` is not bound in aggregate artifact hashes",
                report_path.display()
            )
            .into());
        };
        if *bound_sha256 != sha256 {
            return Err(format!(
                "{} child report `{label}` sha256 does not match aggregate artifact binding",
                report_path.display()
            )
            .into());
        }
    }
    let expected_labels = expected_children
        .iter()
        .map(|expected| expected.label.to_owned())
        .collect::<BTreeSet<_>>();
    if labels != expected_labels {
        return Err(format!(
            "{} child report labels do not match exact expected set",
            report_path.display()
        )
        .into());
    }
    if report.get("proof_report_count").and_then(JsonValue::as_u64) != Some(proof_count) {
        return Err(format!(
            "{} proof_report_count does not match child reports",
            report_path.display()
        )
        .into());
    }
    if report
        .get("diagnostic_report_count")
        .and_then(JsonValue::as_u64)
        != Some(diagnostic_count)
    {
        return Err(format!(
            "{} diagnostic_report_count does not match child reports",
            report_path.display()
        )
        .into());
    }
    let plan_executor_count = report
        .get("plan_executor_report_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing plan_executor_report_count",
                report_path.display()
            )
        })?;
    let no_fallback_count = report
        .get("no_fallback_plan_executor_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing no_fallback_plan_executor_count",
                report_path.display()
            )
        })?;
    if plan_executor_count == 0 || no_fallback_count != plan_executor_count {
        return Err(format!(
            "{} no-fallback plan executor count {no_fallback_count} does not match plan executor report count {plan_executor_count}",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

const NATIVE_GPU_HANDOFF_MANIFEST_PATH: &str = "docs/architecture/native_gpu_handoff_manifest.json";
const NATIVE_GPU_HANDOFF_MANIFEST_JSON: &str =
    include_str!("../../../docs/architecture/native_gpu_handoff_manifest.json");

fn native_gpu_handoff_manifest_json() -> RuntimeResult<JsonValue> {
    Ok(serde_json::from_str(NATIVE_GPU_HANDOFF_MANIFEST_JSON)?)
}

fn verify_native_gpu_all_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    if report.get("aggregate_scope").and_then(JsonValue::as_str)
        != Some("agents-native-gpu-handoff")
    {
        return Err(format!(
            "{} has invalid aggregate_scope for native GPU handoff aggregate",
            report_path.display()
        )
        .into());
    }
    if report.get("check_existing").and_then(JsonValue::as_bool) != Some(true) {
        return Err(format!(
            "{} native GPU handoff aggregate did not run with --check-existing",
            report_path.display()
        )
        .into());
    }
    if report
        .get("handoff_manifest_path")
        .and_then(JsonValue::as_str)
        != Some(NATIVE_GPU_HANDOFF_MANIFEST_PATH)
    {
        return Err(format!(
            "{} native GPU handoff aggregate has wrong handoff_manifest_path",
            report_path.display()
        )
        .into());
    }
    if !report
        .get("handoff_manifest_sha256")
        .and_then(JsonValue::as_str)
        .is_some_and(is_sha256_hex)
    {
        return Err(format!(
            "{} native GPU handoff aggregate missing valid handoff_manifest_sha256",
            report_path.display()
        )
        .into());
    }
    let manifest = native_gpu_handoff_manifest_json()?;
    if report
        .get("handoff_manifest_id")
        .and_then(JsonValue::as_str)
        != manifest.get("manifest_id").and_then(JsonValue::as_str)
    {
        return Err(format!(
            "{} native GPU handoff aggregate manifest id does not match canonical manifest",
            report_path.display()
        )
        .into());
    }
    if report
        .get("handoff_manifest_version")
        .and_then(JsonValue::as_u64)
        != manifest.get("manifest_version").and_then(JsonValue::as_u64)
    {
        return Err(format!(
            "{} native GPU handoff aggregate manifest version does not match canonical manifest",
            report_path.display()
        )
        .into());
    }
    let manifest_reports = manifest
        .get("reports")
        .and_then(JsonValue::as_array)
        .ok_or("canonical native GPU handoff manifest missing reports array")?;
    let required_count = json_u64_field(report, "required_report_count")?;
    let checked_count = json_u64_field(report, "checked_report_count")?;
    let missing_count = json_u64_field(report, "missing_report_count")?;
    let passed_count = json_u64_field(report, "passed_report_count")?;
    let failed_count = json_u64_field(report, "failed_report_count")?;
    if required_count != manifest_reports.len() as u64 {
        return Err(format!(
            "{} native GPU required_report_count {required_count} does not match manifest count {}",
            report_path.display(),
            manifest_reports.len()
        )
        .into());
    }
    if checked_count + missing_count != required_count {
        return Err(format!(
            "{} native GPU checked_report_count + missing_report_count does not match required_report_count",
            report_path.display()
        )
        .into());
    }
    if passed_count + failed_count != checked_count {
        return Err(format!(
            "{} native GPU passed_report_count + failed_report_count does not match checked_report_count",
            report_path.display()
        )
        .into());
    }

    let required_reports = report
        .get("required_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing required_reports", report_path.display()))?;
    let child_reports = report
        .get("child_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing child_reports", report_path.display()))?;
    if required_reports.len() as u64 != required_count {
        return Err(format!(
            "{} required_reports length does not match required_report_count",
            report_path.display()
        )
        .into());
    }
    if child_reports.len() as u64 != required_count {
        return Err(format!(
            "{} child_reports length does not match required_report_count",
            report_path.display()
        )
        .into());
    }

    let mut required_by_label = BTreeMap::new();
    for (index, required) in required_reports.iter().enumerate() {
        let label = required
            .get("label")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} required_reports[{index}] missing label",
                    report_path.display()
                )
            })?;
        if required_by_label.insert(label, required).is_some() {
            return Err(format!(
                "{} duplicate required report label `{label}`",
                report_path.display()
            )
            .into());
        }
    }
    let mut child_by_label = BTreeMap::new();
    for (index, child) in child_reports.iter().enumerate() {
        let label = child
            .get("label")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child_reports[{index}] missing label",
                    report_path.display()
                )
            })?;
        if child_by_label.insert(label, child).is_some() {
            return Err(format!(
                "{} duplicate child report label `{label}`",
                report_path.display()
            )
            .into());
        }
    }

    let mut expected_dependency_edges = BTreeSet::new();
    for manifest_report in manifest_reports {
        let label = json_object_str(manifest_report, "label", report_path)?;
        let required = required_by_label.get(label).ok_or_else(|| {
            format!(
                "{} required_reports missing manifest label `{label}`",
                report_path.display()
            )
        })?;
        let child = child_by_label.get(label).ok_or_else(|| {
            format!(
                "{} child_reports missing manifest label `{label}`",
                report_path.display()
            )
        })?;
        for key in ["path", "command"] {
            if required.get(key).and_then(JsonValue::as_str)
                != manifest_report.get(key).and_then(JsonValue::as_str)
            {
                return Err(format!(
                    "{} required report `{label}` field `{key}` does not match manifest",
                    report_path.display()
                )
                .into());
            }
            if child.get(key).and_then(JsonValue::as_str)
                != manifest_report.get(key).and_then(JsonValue::as_str)
            {
                return Err(format!(
                    "{} child report `{label}` field `{key}` does not match manifest",
                    report_path.display()
                )
                .into());
            }
        }
        if required.get("required_argv") != manifest_report.get("required_argv")
            || child.get("required_argv") != manifest_report.get("required_argv")
        {
            return Err(format!(
                "{} native report `{label}` required_argv does not match manifest",
                report_path.display()
            )
            .into());
        }
        for key in ["max_report_bytes", "max_sidecar_bytes"] {
            if required.get(key).and_then(JsonValue::as_u64)
                != manifest_report.get(key).and_then(JsonValue::as_u64)
            {
                return Err(format!(
                    "{} required report `{label}` field `{key}` does not match manifest",
                    report_path.display()
                )
                .into());
            }
        }
        let manifest_requires_contract = manifest_report
            .get("requires_native_gpu_contract")
            .and_then(JsonValue::as_bool)
            .unwrap_or(true);
        if required
            .get("requires_native_gpu_contract")
            .and_then(JsonValue::as_bool)
            != Some(manifest_requires_contract)
        {
            return Err(format!(
                "{} required report `{label}` requires_native_gpu_contract does not match manifest",
                report_path.display()
            )
            .into());
        }
        let manifest_dependencies = manifest_report
            .get("upstream_dependencies")
            .and_then(JsonValue::as_array)
            .cloned()
            .unwrap_or_default();
        let required_dependencies = required
            .get("upstream_dependencies")
            .and_then(JsonValue::as_array)
            .cloned()
            .unwrap_or_default();
        if required_dependencies != manifest_dependencies {
            return Err(format!(
                "{} required report `{label}` upstream_dependencies do not match manifest",
                report_path.display()
            )
            .into());
        }
        if child
            .get("refresh_argv")
            .and_then(JsonValue::as_array)
            .is_none_or(|argv| argv.is_empty())
        {
            return Err(format!(
                "{} child report `{label}` missing refresh_argv",
                report_path.display()
            )
            .into());
        }
        for dependency in &manifest_dependencies {
            let dependency_label = json_object_str(dependency, "label", report_path)?;
            let dependency_kind = dependency
                .get("kind")
                .and_then(JsonValue::as_str)
                .unwrap_or("consumes-native-report");
            let owner_aggregate = dependency
                .get("owner_aggregate")
                .and_then(JsonValue::as_str)
                .unwrap_or("verify-native-gpu-all");
            let owner_aggregate_report_path = dependency
                .get("owner_aggregate_report_path")
                .and_then(JsonValue::as_str)
                .unwrap_or("target/reports/native-gpu-all.json");
            expected_dependency_edges.insert((
                label.to_owned(),
                dependency_label.to_owned(),
                dependency_kind.to_owned(),
                owner_aggregate.to_owned(),
                owner_aggregate_report_path.to_owned(),
            ));
        }
    }

    verify_native_gpu_all_dependency_graph(
        report,
        report_path,
        &expected_dependency_edges,
        &required_by_label,
    )?;
    verify_native_gpu_all_refresh_taxonomy(report, report_path)?;
    verify_native_gpu_all_refresh_commands(report, report_path)?;
    Ok(())
}

fn verify_native_gpu_all_dependency_graph(
    report: &JsonValue,
    report_path: &Path,
    expected_dependency_edges: &BTreeSet<(String, String, String, String, String)>,
    required_by_label: &BTreeMap<&str, &JsonValue>,
) -> RuntimeResult<()> {
    let graph = report
        .get("report_dependency_graph")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} missing report_dependency_graph", report_path.display()))?;
    if graph.get("kind").and_then(JsonValue::as_str) != Some("report-dependency-dag-v1") {
        return Err(format!(
            "{} native report_dependency_graph has invalid kind",
            report_path.display()
        )
        .into());
    }
    if graph.get("owner").and_then(JsonValue::as_str) != Some("verify-native-gpu-all") {
        return Err(format!(
            "{} native report_dependency_graph has invalid owner",
            report_path.display()
        )
        .into());
    }
    if graph.get("source").and_then(JsonValue::as_str) != Some("native_gpu_handoff_manifest") {
        return Err(format!(
            "{} native report_dependency_graph source must be native_gpu_handoff_manifest",
            report_path.display()
        )
        .into());
    }
    let upstream_dependency_count = json_u64_field(report, "upstream_dependency_count")?;
    if upstream_dependency_count != expected_dependency_edges.len() as u64 {
        return Err(format!(
            "{} upstream_dependency_count {upstream_dependency_count} does not match manifest dependency count {}",
            report_path.display(),
            expected_dependency_edges.len()
        )
        .into());
    }
    for key in [
        "upstream_dependency_count",
        "upstream_dependency_refresh_debt_count",
        "upstream_dependency_true_blocker_count",
    ] {
        if graph.get(key).and_then(JsonValue::as_u64) != report.get(key).and_then(JsonValue::as_u64)
        {
            return Err(format!(
                "{} report_dependency_graph `{key}` does not match top-level count",
                report_path.display()
            )
            .into());
        }
    }
    let edges = graph
        .get("edges")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} report_dependency_graph missing edges",
                report_path.display()
            )
        })?;
    let upstream_reports = graph
        .get("upstream_reports")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} report_dependency_graph missing upstream_reports",
                report_path.display()
            )
        })?;
    if edges.len() != expected_dependency_edges.len()
        || upstream_reports.len() != expected_dependency_edges.len()
    {
        return Err(format!(
            "{} report_dependency_graph edge/upstream_report lengths do not match manifest dependencies",
            report_path.display()
        )
        .into());
    }
    let mut observed_edges = BTreeSet::new();
    for edge in edges {
        let from = json_object_str(edge, "from", report_path)?;
        let to = json_object_str(edge, "to", report_path)?;
        let kind = json_object_str(edge, "kind", report_path)?;
        if kind != "consumes-native-report" {
            return Err(format!(
                "{} report_dependency_graph edge {from}->{to} must consume a native report",
                report_path.display()
            )
            .into());
        }
        let owner_aggregate = json_object_str(edge, "owner_aggregate", report_path)?;
        let owner_aggregate_report_path =
            json_object_str(edge, "owner_aggregate_report_path", report_path)?;
        if owner_aggregate != "verify-native-gpu-all" {
            return Err(format!(
                "{} report_dependency_graph edge {from}->{to} must be owned by verify-native-gpu-all",
                report_path.display()
            )
            .into());
        }
        observed_edges.insert((
            from.to_owned(),
            to.to_owned(),
            kind.to_owned(),
            owner_aggregate.to_owned(),
            owner_aggregate_report_path.to_owned(),
        ));
    }
    if &observed_edges != expected_dependency_edges {
        return Err(format!(
            "{} report_dependency_graph edges do not match manifest upstream_dependencies",
            report_path.display()
        )
        .into());
    }
    let mut observed_upstream_reports = BTreeSet::new();
    for upstream in upstream_reports {
        let label = json_object_str(upstream, "label", report_path)?;
        let required_by = json_object_str(upstream, "required_by", report_path)?;
        let kind = json_object_str(upstream, "kind", report_path)?;
        let owner_aggregate = json_object_str(upstream, "owner_aggregate", report_path)?;
        let owner_aggregate_report_path =
            json_object_str(upstream, "owner_aggregate_report_path", report_path)?;
        if !required_by_label.contains_key(required_by) {
            return Err(format!(
                "{} upstream report `{label}` references unknown required_by `{required_by}`",
                report_path.display()
            )
            .into());
        }
        if kind != "consumes-native-report" {
            return Err(format!(
                "{} upstream report `{label}` must consume a native report",
                report_path.display()
            )
            .into());
        }
        if owner_aggregate != "verify-native-gpu-all" {
            return Err(format!(
                "{} upstream report `{label}` must be owned by verify-native-gpu-all",
                report_path.display()
            )
            .into());
        }
        for key in [
            "exists",
            "schema_valid",
            "git_fresh",
            "worktree_fresh",
            "artifact_hashes_fresh",
            "freshness_debt",
            "true_blocker",
        ] {
            if upstream.get(key).and_then(JsonValue::as_bool).is_none() {
                return Err(format!(
                    "{} upstream report `{label}` missing boolean `{key}`",
                    report_path.display()
                )
                .into());
            }
        }
        observed_upstream_reports.insert((
            required_by.to_owned(),
            label.to_owned(),
            kind.to_owned(),
            owner_aggregate.to_owned(),
            owner_aggregate_report_path.to_owned(),
        ));
    }
    if &observed_upstream_reports != expected_dependency_edges {
        return Err(format!(
            "{} report_dependency_graph upstream_reports do not match manifest upstream_dependencies",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

fn verify_native_gpu_all_refresh_taxonomy(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    let taxonomy = report
        .get("failure_taxonomy")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} missing failure_taxonomy", report_path.display()))?;
    for key in [
        "missing_report_count",
        "report_size_failure_count",
        "sidecar_size_failure_count",
        "schema_file_contract_failure_count",
        "schema_file_freshness_failure_count",
        "schema_shape_contract_failure_count",
        "schema_shape_freshness_failure_count",
        "native_product_contract_failure_count",
        "native_refresh_first_product_contract_count",
        "native_contract_freshness_failure_count",
        "all_steps_failure_count",
        "status_failure_count",
        "git_stale_count",
        "worktree_stale_count",
        "binary_stale_count",
        "identity_fast_refresh_child_count",
        "refresh_debt_child_count",
        "true_blocker_child_count",
        "product_contract_child_count",
        "refresh_first_product_contract_child_count",
        "upstream_dependency_refresh_debt_count",
        "upstream_dependency_true_blocker_count",
    ] {
        if taxonomy.get(key).and_then(JsonValue::as_u64).is_none() {
            return Err(format!(
                "{} failure_taxonomy missing numeric `{key}`",
                report_path.display()
            )
            .into());
        }
    }
    for key in [
        "missing_report_count",
        "identity_fast_refresh_child_count",
        "refresh_debt_child_count",
        "true_blocker_child_count",
        "product_contract_child_count",
        "refresh_first_product_contract_child_count",
        "upstream_dependency_refresh_debt_count",
        "upstream_dependency_true_blocker_count",
    ] {
        if taxonomy.get(key).and_then(JsonValue::as_u64)
            != report.get(key).and_then(JsonValue::as_u64)
        {
            return Err(format!(
                "{} failure_taxonomy `{key}` does not match top-level count",
                report_path.display()
            )
            .into());
        }
    }
    let true_blocker_children = report
        .get("true_blocker_children")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing true_blocker_children", report_path.display()))?;
    let true_blocker_child_count = report
        .get("true_blocker_child_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing true_blocker_child_count", report_path.display()))?;
    if true_blocker_children.len() as u64 != true_blocker_child_count {
        return Err(format!(
            "{} true_blocker_children length does not match true_blocker_child_count",
            report_path.display()
        )
        .into());
    }
    if report
        .get("aggregate_checks_pass")
        .and_then(JsonValue::as_bool)
        .is_none()
    {
        return Err(format!(
            "{} missing boolean aggregate_checks_pass",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

fn verify_native_gpu_all_refresh_commands(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    let refresh_commands = report
        .get("refresh_commands")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| format!("{} missing refresh_commands", report_path.display()))?;
    for (index, command) in refresh_commands.iter().enumerate() {
        let label = json_object_str(command, "label", report_path)?;
        if json_object_str(command, "path", report_path)?
            .trim()
            .is_empty()
            || json_object_str(command, "reason", report_path)?
                .trim()
                .is_empty()
            || json_object_str(command, "command", report_path)?
                .trim()
                .is_empty()
        {
            return Err(format!(
                "{} refresh_commands[{index}] for `{label}` has empty path/reason/command",
                report_path.display()
            )
            .into());
        }
        let argv = command
            .get("argv")
            .and_then(JsonValue::as_array)
            .ok_or_else(|| {
                format!(
                    "{} refresh_commands[{index}] for `{label}` missing argv",
                    report_path.display()
                )
            })?;
        if argv.is_empty()
            || argv
                .iter()
                .any(|arg| arg.as_str().is_none_or(|arg| arg.trim().is_empty()))
        {
            return Err(format!(
                "{} refresh_commands[{index}] for `{label}` has malformed argv",
                report_path.display()
            )
            .into());
        }
        let argv_strings = argv
            .iter()
            .filter_map(JsonValue::as_str)
            .collect::<Vec<_>>();
        let executable = argv_strings
            .first()
            .and_then(|arg| Path::new(arg).file_name())
            .and_then(std::ffi::OsStr::to_str)
            .unwrap_or_default();
        let command_name = argv_strings.get(1).copied().unwrap_or_default();
        if executable.starts_with("boon_cli") {
            return Err(format!(
                "{} refresh_commands[{index}] for `{label}` must not use boon_cli in native aggregate refresh",
                report_path.display()
            )
            .into());
        }
        if matches!(
            command_name,
            "run"
                | "run-plan"
                | "run-plan-route"
                | "run-plan-root-scalar-scenario"
                | "run-plan-scenario-events"
        ) {
            return Err(format!(
                "{} refresh_commands[{index}] for `{label}` uses source-replay command `{command_name}` in native aggregate refresh",
                report_path.display()
            )
            .into());
        }
        if argv_strings.iter().any(|arg| {
            matches!(
                *arg,
                "--compare-legacy" | "--diagnostic-compare-legacy" | "--engine"
            )
        }) {
            return Err(format!(
                "{} refresh_commands[{index}] for `{label}` contains retired legacy comparison or engine flags",
                report_path.display()
            )
            .into());
        }
    }
    Ok(())
}

fn json_object_str<'a>(
    value: &'a JsonValue,
    key: &str,
    report_path: &Path,
) -> RuntimeResult<&'a str> {
    value.get(key).and_then(JsonValue::as_str).ok_or_else(|| {
        format!(
            "{} JSON object missing string `{key}`",
            report_path.display()
        )
        .into()
    })
}

fn report_array_or_json_sidecar(
    report: &JsonValue,
    report_path: &Path,
    pointer: &str,
) -> RuntimeResult<Vec<JsonValue>> {
    let value = report
        .pointer(pointer)
        .ok_or_else(|| format!("{} missing {pointer}", report_path.display()))?;
    if let Some(array) = value.as_array() {
        return Ok(array.clone());
    }
    if value.get("kind").and_then(JsonValue::as_str) != Some("json-sidecar-ref")
        || value.get("sidecar").and_then(JsonValue::as_bool) != Some(true)
    {
        return Err(format!(
            "{} {pointer} must be an inline array or json-sidecar-ref",
            report_path.display()
        )
        .into());
    }
    let sidecar_path = value
        .get("path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} {pointer} sidecar missing path", report_path.display()))?;
    let expected_sha256 = value
        .get("sha256")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} {pointer} sidecar missing sha256", report_path.display()))?;
    let expected_byte_len = value
        .get("byte_len")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} {pointer} sidecar missing byte_len",
                report_path.display()
            )
        })?;
    let metadata_byte_len = fs::metadata(sidecar_path)?.len();
    if metadata_byte_len != expected_byte_len {
        return Err(format!(
            "{} {pointer} sidecar `{sidecar_path}` byte_len is stale: report={expected_byte_len}, fs={metadata_byte_len}",
            report_path.display()
        )
        .into());
    }
    let actual_sha256 = sha256_file(Path::new(sidecar_path))?;
    if actual_sha256 != expected_sha256 {
        return Err(format!(
            "{} {pointer} sidecar `{sidecar_path}` sha256 is stale",
            report_path.display()
        )
        .into());
    }
    let sidecar_file = fs::File::open(sidecar_path)?;
    let sidecar_json: JsonValue = serde_json::from_reader(BufReader::new(sidecar_file))?;
    sidecar_json.as_array().cloned().ok_or_else(|| {
        format!(
            "{} {pointer} sidecar `{sidecar_path}` must contain a JSON array",
            report_path.display()
        )
        .into()
    })
}

fn verify_report_refresh_queue_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let selected_count = report
        .get("selected_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing selected_count", report_path.display()))?;
    let selection_mode = report
        .get("selection_mode")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing selection_mode", report_path.display()))?;
    if !matches!(
        selection_mode,
        "dependency-order-full-queue" | "dependency-expanded-label-filter"
    ) {
        return Err(format!(
            "{} invalid selection_mode `{selection_mode}`",
            report_path.display()
        )
        .into());
    }
    let dependency_expansion_count = report
        .get("dependency_expansion_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing dependency_expansion_count",
                report_path.display()
            )
        })?;
    let dependency_deferred_count = report
        .get("dependency_deferred_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing dependency_deferred_count",
                report_path.display()
            )
        })?;
    if dependency_expansion_count + dependency_deferred_count > selected_count {
        return Err(format!(
            "{} dependency expansion/deferred counts cannot exceed selected_count",
            report_path.display()
        )
        .into());
    }
    let pass_count = report
        .get("pass_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing pass_count", report_path.display()))?;
    let fail_count = report
        .get("fail_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing fail_count", report_path.display()))?;
    let run_count = report
        .get("run_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing run_count", report_path.display()))?;
    let missing_argv_count = report
        .get("missing_argv_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing missing_argv_count", report_path.display()))?;
    let invalid_command_count = report
        .get("invalid_command_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing invalid_command_count", report_path.display()))?;
    let total_result_count = pass_count + fail_count;
    if total_result_count < selected_count {
        return Err(format!(
            "{} pass_count + fail_count must be at least selected_count",
            report_path.display()
        )
        .into());
    }
    if run_count > total_result_count {
        return Err(format!(
            "{} run_count cannot exceed pass_count + fail_count",
            report_path.display()
        )
        .into());
    }
    let dry_run = report.get("dry_run").and_then(JsonValue::as_bool) == Some(true);
    if dry_run && run_count != 0 {
        return Err(format!(
            "{} dry-run queue has nonzero run_count",
            report_path.display()
        )
        .into());
    }
    let closed_loop_requested = report
        .get("closed_loop_requested")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| format!("{} missing closed_loop_requested", report_path.display()))?;
    if (!closed_loop_requested || dry_run) && total_result_count != selected_count {
        return Err(format!(
            "{} non-closed-loop refresh queue must have pass_count + fail_count equal selected_count",
            report_path.display()
        )
        .into());
    }
    let closed_loop_max_runs = report
        .get("closed_loop_max_runs")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| format!("{} missing closed_loop_max_runs", report_path.display()))?;
    if closed_loop_max_runs == 0 {
        return Err(format!(
            "{} closed_loop_max_runs must be positive",
            report_path.display()
        )
        .into());
    }
    let closed_loop_stop_reason = report
        .get("closed_loop_stop_reason")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing closed_loop_stop_reason", report_path.display()))?;
    if !matches!(
        closed_loop_stop_reason,
        "not-requested"
            | "dry-run"
            | "clean"
            | "selected-label-burndown"
            | "no-refresh-commands"
            | "post-aggregate-unavailable"
            | "refresh-command-failed"
            | "aggregate-rerun-failed"
            | "max-runs"
    ) {
        return Err(format!(
            "{} invalid closed_loop_stop_reason `{closed_loop_stop_reason}`",
            report_path.display()
        )
        .into());
    }
    let closed_loop_executed_run_count = report
        .get("closed_loop_executed_run_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing closed_loop_executed_run_count",
                report_path.display()
            )
        })?;
    if closed_loop_executed_run_count > run_count {
        return Err(format!(
            "{} closed_loop_executed_run_count cannot exceed run_count",
            report_path.display()
        )
        .into());
    }
    for key in [
        "closed_loop_final_refresh_debt_child_count",
        "closed_loop_final_selected_refresh_command_count",
    ] {
        if report.get(key).and_then(JsonValue::as_u64).is_none() {
            return Err(format!("{} missing {key}", report_path.display()).into());
        }
    }
    let closed_loop_cycles =
        report_array_or_json_sidecar(report, report_path, "/closed_loop_cycles")?;
    if !closed_loop_requested && closed_loop_stop_reason != "not-requested" {
        return Err(format!(
            "{} non-closed-loop report must use closed_loop_stop_reason=not-requested",
            report_path.display()
        )
        .into());
    }
    if dry_run && closed_loop_requested && closed_loop_stop_reason != "dry-run" {
        return Err(format!(
            "{} dry-run closed-loop report must use closed_loop_stop_reason=dry-run",
            report_path.display()
        )
        .into());
    }
    for (index, cycle) in closed_loop_cycles.iter().enumerate() {
        for key in [
            "cycle",
            "pre_refresh_debt_child_count",
            "selected_count",
            "skipped_label_count",
            "run_count",
            "pass_count",
            "fail_count",
            "missing_argv_count",
            "invalid_command_count",
        ] {
            if cycle.get(key).and_then(JsonValue::as_u64).is_none() {
                return Err(format!(
                    "{} closed_loop_cycles[{index}] missing numeric {key}",
                    report_path.display()
                )
                .into());
            }
        }
        if cycle
            .get("selected_labels")
            .and_then(JsonValue::as_array)
            .is_none()
        {
            return Err(format!(
                "{} closed_loop_cycles[{index}] missing selected_labels",
                report_path.display()
            )
            .into());
        }
        verify_refresh_queue_boon_cli_prebuild(
            cycle.get("boon_cli_prebuild").ok_or_else(|| {
                format!(
                    "{} closed_loop_cycles[{index}] missing boon_cli_prebuild",
                    report_path.display()
                )
            })?,
            report_path,
            &format!("closed_loop_cycles[{index}].boon_cli_prebuild"),
        )?;
        if cycle.get("owner_aggregate_rerun_requested").is_some()
            || cycle.get("owner_aggregate_rerun_executed").is_some()
            || cycle.get("owner_aggregate_rerun_count").is_some()
            || cycle.get("owner_aggregate_reruns").is_some()
        {
            let owner_requested = cycle
                .get("owner_aggregate_rerun_requested")
                .and_then(JsonValue::as_bool)
                .ok_or_else(|| {
                    format!(
                        "{} closed_loop_cycles[{index}] missing owner_aggregate_rerun_requested",
                        report_path.display()
                    )
                })?;
            let owner_executed = cycle
                .get("owner_aggregate_rerun_executed")
                .and_then(JsonValue::as_bool)
                .ok_or_else(|| {
                    format!(
                        "{} closed_loop_cycles[{index}] missing owner_aggregate_rerun_executed",
                        report_path.display()
                    )
                })?;
            let owner_count = cycle
                .get("owner_aggregate_rerun_count")
                .and_then(JsonValue::as_u64)
                .ok_or_else(|| {
                    format!(
                        "{} closed_loop_cycles[{index}] missing owner_aggregate_rerun_count",
                        report_path.display()
                    )
                })?;
            let owner_reruns = cycle
                .get("owner_aggregate_reruns")
                .and_then(JsonValue::as_array)
                .ok_or_else(|| {
                    format!(
                        "{} closed_loop_cycles[{index}] missing owner_aggregate_reruns",
                        report_path.display()
                    )
                })?;
            if owner_count != owner_reruns.len() as u64 {
                return Err(format!(
                    "{} closed_loop_cycles[{index}] owner_aggregate_rerun_count does not match owner_aggregate_reruns length",
                    report_path.display()
                )
                .into());
            }
            if dry_run && owner_executed {
                return Err(format!(
                    "{} closed_loop_cycles[{index}] dry-run cannot execute owner aggregate reruns",
                    report_path.display()
                )
                .into());
            }
            if owner_executed && !owner_requested {
                return Err(format!(
                    "{} closed_loop_cycles[{index}] owner aggregate rerun cannot execute unless requested",
                    report_path.display()
                )
                .into());
            }
        }
    }
    let results = report_array_or_json_sidecar(report, report_path, "/results")?;
    if results.len() as u64 != total_result_count {
        return Err(format!(
            "{} results length {} does not match pass_count + fail_count {total_result_count}",
            report_path.display(),
            results.len()
        )
        .into());
    }
    let mut observed_fail_count = 0_u64;
    let mut observed_pass_count = 0_u64;
    for (index, result) in results.iter().enumerate() {
        let label = result
            .get("label")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| format!("{} results[{index}] missing label", report_path.display()))?;
        if label.trim().is_empty() {
            return Err(format!("{} results[{index}] empty label", report_path.display()).into());
        }
        let status = result
            .get("status")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| format!("{} results[{index}] missing status", report_path.display()))?;
        match status {
            "pass" => observed_pass_count += 1,
            "dry-run" => {
                observed_pass_count += 1;
                if !dry_run {
                    return Err(format!(
                        "{} results[{index}] is dry-run while report.dry_run=false",
                        report_path.display()
                    )
                    .into());
                }
            }
            "fail" => observed_fail_count += 1,
            other => {
                return Err(format!(
                    "{} results[{index}] has invalid status `{other}`",
                    report_path.display()
                )
                .into());
            }
        }
    }
    if observed_pass_count != pass_count || observed_fail_count != fail_count {
        return Err(format!(
            "{} result statuses do not match pass_count/fail_count",
            report_path.display()
        )
        .into());
    }
    if report.get("status").and_then(JsonValue::as_str) == Some("pass") && fail_count != 0 {
        return Err(format!(
            "{} passing refresh queue has failed child results",
            report_path.display()
        )
        .into());
    }
    if missing_argv_count > fail_count || invalid_command_count > fail_count {
        return Err(format!(
            "{} missing/invalid command counts cannot exceed fail_count",
            report_path.display()
        )
        .into());
    }
    let execution_plan =
        report_array_or_json_sidecar(report, report_path, "/refresh_execution_plan")?;
    if execution_plan.len() as u64 != selected_count {
        return Err(format!(
            "{} refresh_execution_plan length {} does not match selected_count {selected_count}",
            report_path.display(),
            execution_plan.len()
        )
        .into());
    }
    let phase_summaries =
        report_array_or_json_sidecar(report, report_path, "/refresh_phase_summaries")?;
    let mut phase_summary_total = 0_u64;
    for (index, summary) in phase_summaries.iter().enumerate() {
        let phase = summary
            .get("refresh_phase")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} refresh_phase_summaries[{index}] missing refresh_phase",
                    report_path.display()
                )
            })?;
        if phase.trim().is_empty() {
            return Err(format!(
                "{} refresh_phase_summaries[{index}] has empty refresh_phase",
                report_path.display()
            )
            .into());
        }
        phase_summary_total += summary
            .get("selected_count")
            .and_then(JsonValue::as_u64)
            .ok_or_else(|| {
                format!(
                    "{} refresh_phase_summaries[{index}] missing selected_count",
                    report_path.display()
                )
            })?;
    }
    if phase_summary_total != selected_count {
        return Err(format!(
            "{} refresh_phase_summaries total {phase_summary_total} does not match selected_count {selected_count}",
            report_path.display()
        )
        .into());
    }
    let selected_labels = report_array_or_json_sidecar(report, report_path, "/selected_labels")?;
    if selected_labels.len() as u64 != selected_count {
        return Err(format!(
            "{} selected_labels length {} does not match selected_count {selected_count}",
            report_path.display(),
            selected_labels.len()
        )
        .into());
    }
    for (index, plan_entry) in execution_plan.iter().enumerate() {
        let label = plan_entry
            .get("label")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} refresh_execution_plan[{index}] missing label",
                    report_path.display()
                )
            })?;
        if label.trim().is_empty() {
            return Err(format!(
                "{} refresh_execution_plan[{index}] empty label",
                report_path.display()
            )
            .into());
        }
        let selected_label = selected_labels
            .get(index)
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} selected_labels[{index}] missing string",
                    report_path.display()
                )
            })?;
        let result_label = results
            .get(index)
            .and_then(|result| result.get("label"))
            .and_then(JsonValue::as_str)
            .ok_or_else(|| format!("{} results[{index}] missing label", report_path.display()))?;
        if label != selected_label || label != result_label {
            return Err(format!(
                "{} refresh_execution_plan[{index}] label does not match selected_labels/results",
                report_path.display()
            )
            .into());
        }
        let phase = plan_entry
            .get("refresh_phase")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} refresh_execution_plan[{index}] missing refresh_phase",
                    report_path.display()
                )
            })?;
        if phase.trim().is_empty() {
            return Err(format!(
                "{} refresh_execution_plan[{index}] empty refresh_phase",
                report_path.display()
            )
            .into());
        }
        if plan_entry
            .get("dependency_depth")
            .and_then(JsonValue::as_u64)
            .is_none()
        {
            return Err(format!(
                "{} refresh_execution_plan[{index}] missing dependency_depth",
                report_path.display()
            )
            .into());
        }
        if plan_entry
            .get("selected_by_label_filter")
            .and_then(JsonValue::as_bool)
            .is_none()
        {
            return Err(format!(
                "{} refresh_execution_plan[{index}] missing selected_by_label_filter",
                report_path.display()
            )
            .into());
        }
    }
    verify_refresh_queue_boon_cli_prebuild(
        report
            .get("boon_cli_prebuild")
            .ok_or_else(|| format!("{} missing boon_cli_prebuild", report_path.display()))?,
        report_path,
        "boon_cli_prebuild",
    )?;
    let owner_rerun_requested = report
        .get("owner_aggregate_rerun_requested")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| {
            format!(
                "{} missing owner_aggregate_rerun_requested",
                report_path.display()
            )
        })?;
    let owner_rerun_executed = report
        .get("owner_aggregate_rerun_executed")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| {
            format!(
                "{} missing owner_aggregate_rerun_executed",
                report_path.display()
            )
        })?;
    let owner_rerun_count = report
        .get("owner_aggregate_rerun_count")
        .and_then(JsonValue::as_u64)
        .ok_or_else(|| {
            format!(
                "{} missing owner_aggregate_rerun_count",
                report_path.display()
            )
        })?;
    let owner_reruns =
        report_array_or_json_sidecar(report, report_path, "/owner_aggregate_reruns")?;
    if owner_rerun_count != owner_reruns.len() as u64 {
        return Err(format!(
            "{} owner_aggregate_rerun_count does not match owner_aggregate_reruns length",
            report_path.display()
        )
        .into());
    }
    if dry_run && owner_rerun_executed {
        return Err(format!(
            "{} dry-run queue cannot execute owner aggregate reruns",
            report_path.display()
        )
        .into());
    }
    if owner_rerun_executed && !owner_rerun_requested {
        return Err(format!(
            "{} owner aggregate rerun cannot execute unless requested",
            report_path.display()
        )
        .into());
    }
    let rerun_requested = report
        .get("post_refresh_aggregate_rerun_requested")
        .and_then(JsonValue::as_bool)
        .unwrap_or(false);
    let rerun_executed = report
        .get("post_refresh_aggregate_rerun_executed")
        .and_then(JsonValue::as_bool)
        .unwrap_or(false);
    let post = report
        .get("post_refresh_aggregate")
        .ok_or_else(|| format!("{} missing post_refresh_aggregate", report_path.display()))?;
    if rerun_requested {
        let post_object = post.as_object().ok_or_else(|| {
            format!(
                "{} post_refresh_aggregate must be an object when rerun is requested",
                report_path.display()
            )
        })?;
        if post_object
            .get("rerun_requested")
            .and_then(JsonValue::as_bool)
            != Some(true)
        {
            return Err(format!(
                "{} post_refresh_aggregate.rerun_requested must be true",
                report_path.display()
            )
            .into());
        }
        if dry_run {
            if rerun_executed {
                return Err(format!(
                    "{} dry-run queue cannot execute post-refresh aggregate",
                    report_path.display()
                )
                .into());
            }
        } else if post_object
            .get("rerun_executed")
            .and_then(JsonValue::as_bool)
            != Some(rerun_executed)
        {
            return Err(format!(
                "{} post_refresh_aggregate.rerun_executed mismatch",
                report_path.display()
            )
            .into());
        }
        if rerun_executed {
            for key in [
                "refresh_debt_child_count",
                "remaining_refresh_command_count",
                "remaining_selected_refresh_command_count",
            ] {
                if post_object.get(key).and_then(JsonValue::as_u64).is_none() {
                    return Err(format!(
                        "{} post_refresh_aggregate missing numeric {key}",
                        report_path.display()
                    )
                    .into());
                }
            }
            let remaining_selected_refresh_commands = report_array_or_json_sidecar(
                report,
                report_path,
                "/post_refresh_aggregate/remaining_selected_refresh_commands",
            )?;
            if post_object
                .get("remaining_selected_refresh_command_count")
                .and_then(JsonValue::as_u64)
                != Some(remaining_selected_refresh_commands.len() as u64)
            {
                return Err(format!(
                    "{} post_refresh_aggregate.remaining_selected_refresh_command_count does not match remaining_selected_refresh_commands length",
                    report_path.display()
                )
                .into());
            }
            if post_object
                .get("selected_burndown")
                .and_then(JsonValue::as_bool)
                .is_none()
            {
                return Err(format!(
                    "{} post_refresh_aggregate missing selected_burndown",
                    report_path.display()
                )
                .into());
            }
        }
    } else if !post.is_null() {
        return Err(format!(
            "{} post_refresh_aggregate must be null unless rerun is requested",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

fn verify_refresh_queue_boon_cli_prebuild(
    prebuild: &JsonValue,
    report_path: &Path,
    field_path: &str,
) -> RuntimeResult<()> {
    let object = prebuild
        .as_object()
        .ok_or_else(|| format!("{} {field_path} must be an object", report_path.display()))?;
    let required = object
        .get("required")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| format!("{} {field_path} missing required", report_path.display()))?;
    let executed = object
        .get("executed")
        .and_then(JsonValue::as_bool)
        .ok_or_else(|| format!("{} {field_path} missing executed", report_path.display()))?;
    let status = object
        .get("status")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} {field_path} missing status", report_path.display()))?;
    if !matches!(status, "not-required" | "skipped-dry-run" | "pass" | "fail") {
        return Err(format!(
            "{} {field_path} has invalid status `{status}`",
            report_path.display()
        )
        .into());
    }
    if !required && status != "not-required" {
        return Err(format!(
            "{} {field_path} must use status=not-required when required=false",
            report_path.display()
        )
        .into());
    }
    if executed {
        if object
            .get("elapsed_ms")
            .and_then(JsonValue::as_f64)
            .is_none()
        {
            return Err(format!(
                "{} {field_path} missing elapsed_ms for executed prebuild",
                report_path.display()
            )
            .into());
        }
        if !matches!(status, "pass" | "fail") {
            return Err(format!(
                "{} {field_path} executed prebuild must use pass/fail status",
                report_path.display()
            )
            .into());
        }
    }
    Ok(())
}

fn verify_child_source_payload_typing_summary(
    child: &JsonValue,
    label: &str,
    report_path: &Path,
) -> RuntimeResult<()> {
    if !matches!(
        label,
        "bytes-source-payload-dump-plan" | "bytes-indexed-source-payload-dump-plan"
    ) {
        return Ok(());
    }
    let summary = child
        .get("source_payload_typing")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} child report `{label}` missing source_payload_typing summary",
                report_path.display()
            )
        })?;
    let complete = summary
        .get("typed_payload_summary_complete")
        .and_then(JsonValue::as_bool)
        == Some(true);
    if !complete {
        return Err(format!(
            "{} child report `{label}` source_payload_typing is incomplete",
            report_path.display()
        )
        .into());
    }
    for (field_name, min_value) in [
        ("source_payload_route_count", 1),
        ("bytes_payload_route_count", 1),
        ("source_payload_update_count", 1),
        ("bytes_source_payload_update_count", 1),
        ("typed_source_payload_operand_count", 1),
        ("typed_payload_descriptor_count", 1),
        ("bytes_typed_payload_descriptor_count", 1),
    ] {
        let actual = summary
            .get(field_name)
            .and_then(JsonValue::as_u64)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` source_payload_typing missing numeric `{field_name}`",
                    report_path.display()
                )
            })?;
        if actual < min_value {
            return Err(format!(
                "{} child report `{label}` source_payload_typing `{field_name}` is {actual}, expected at least {min_value}",
                report_path.display()
            )
            .into());
        }
    }
    let typed_fields = summary
        .get("typed_fields")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} child report `{label}` source_payload_typing missing array `typed_fields`",
                report_path.display()
            )
        })?;
    let mut typed_entries = BTreeSet::new();
    for entry in typed_fields {
        let object = entry.as_object().ok_or_else(|| {
            format!(
                "{} child report `{label}` source_payload_typing `typed_fields` contains non-object value",
                report_path.display()
            )
        })?;
        let field = object.get("field").and_then(JsonValue::as_str).ok_or_else(|| {
            format!(
                "{} child report `{label}` source_payload_typing typed field missing string `field`",
                report_path.display()
            )
        })?;
        let value_type = object
            .get("value_type")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` source_payload_typing typed field missing string `value_type`",
                    report_path.display()
                )
            })?;
        typed_entries.insert((field.to_owned(), value_type.to_owned()));
    }
    if typed_entries.len() != typed_fields.len() {
        return Err(format!(
            "{} child report `{label}` source_payload_typing `typed_fields` contains duplicates",
            report_path.display()
        )
        .into());
    }
    if !typed_entries.contains(&("Bytes".to_owned(), "bytes".to_owned())) {
        return Err(format!(
            "{} child report `{label}` source_payload_typing typed_fields do not contain `Bytes`/`bytes`: {:?}",
            report_path.display(),
            typed_entries
        )
        .into());
    }
    for field_name in ["fields", "update_fields", "operand_fields"] {
        let fields = summary
            .get(field_name)
            .and_then(JsonValue::as_array)
            .ok_or_else(|| {
                format!(
                    "{} child report `{label}` source_payload_typing missing array `{field_name}`",
                    report_path.display()
                )
            })?;
        let values = fields
            .iter()
            .map(|field| {
                field.as_str().map(str::to_owned).ok_or_else(|| {
                    format!(
                        "{} child report `{label}` source_payload_typing `{field_name}` contains non-string value",
                        report_path.display()
                    )
                    .into()
                })
            })
            .collect::<RuntimeResult<BTreeSet<_>>>()?;
        if values.len() != fields.len() {
            return Err(format!(
                "{} child report `{label}` source_payload_typing `{field_name}` contains duplicates",
                report_path.display()
            )
            .into());
        }
        if !values.contains("Bytes") {
            return Err(format!(
                "{} child report `{label}` source_payload_typing `{field_name}` does not contain `Bytes`: {:?}",
                report_path.display(),
                values
            )
            .into());
        }
    }
    Ok(())
}

fn verify_child_expression_kind_coverage(
    child: &JsonValue,
    label: &str,
    report_path: &Path,
) -> RuntimeResult<()> {
    let expected = expected_bytes_child_expression_kinds(label);
    let kinds = child
        .get("expression_kinds")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} child report `{label}` missing expression_kinds coverage summary",
                report_path.display()
            )
        })?;
    let actual = kinds
        .iter()
        .map(|kind| {
            kind.as_str().map(str::to_owned).ok_or_else(|| {
                format!(
                    "{} child report `{label}` expression_kinds contains non-string value",
                    report_path.display()
                )
                .into()
            })
        })
        .collect::<RuntimeResult<BTreeSet<_>>>()?;
    if actual.len() != kinds.len() {
        return Err(format!(
            "{} child report `{label}` expression_kinds contains duplicates",
            report_path.display()
        )
        .into());
    }
    let expected_set = expected
        .iter()
        .map(|kind| (*kind).to_owned())
        .collect::<BTreeSet<_>>();
    if !expected_set.is_subset(&actual) {
        return Err(format!(
            "{} child report `{label}` expression_kinds {:?} do not include expected {:?}",
            report_path.display(),
            actual,
            expected_set
        )
        .into());
    }
    Ok(())
}

fn expected_bytes_child_expression_kinds(label: &str) -> &'static [&'static str] {
    match label {
        "bytes-search-scenario" => &[
            "bytes_concat",
            "bytes_find",
            "bytes_starts_with",
            "bytes_ends_with",
        ],
        "bytes-encoding-scenario" => &[
            "bytes_concat",
            "bytes_to_hex",
            "bytes_to_base64",
            "bytes_zeros",
            "bytes_from_hex",
            "bytes_from_base64",
            "bytes_length",
            "bytes_get",
        ],
        "bytes-numeric-scenario" => &[
            "bytes_read_unsigned",
            "bytes_read_signed",
            "bytes_write_unsigned",
            "bytes_write_signed",
            "bytes_to_hex",
        ],
        "bytes-set-conversion-bank-dump-plan" | "bytes-set-conversion-bank-scenario" => &[
            "bytes_set",
            "bytes_to_text",
            "bytes_to_hex",
            "bytes_to_base64",
        ],
        "bytes-constant-expr-dump-plan" | "bytes-constant-expr-scenario" => &[
            "bytes_get",
            "bytes_slice",
            "bytes_read_unsigned",
            "bytes_write_unsigned",
        ],
        "bytes-dynamic-slice-dump-plan" | "bytes-dynamic-slice-scenario" => {
            &["bytes_slice", "bytes_length", "bytes_get"]
        }
        "cells-dump-plan" => &[
            "text_to_bytes",
            "bytes_find",
            "bytes_starts_with",
            "bytes_slice",
        ],
        "bytes-same-event-dependency-scenario" => &["bytes_set", "bytes_get", "bytes_length"],
        "bytes-indexed-same-event-dependency-scenario" => {
            &["source_payload", "bytes_set", "bytes_get", "bytes_length"]
        }
        "bytes-indexed-search-scenario" => &[
            "source_payload",
            "bytes_is_empty",
            "bytes_to_hex",
            "bytes_to_base64",
            "bytes_to_text",
            "text_to_bytes",
            "bytes_from_hex",
            "bytes_from_base64",
            "bytes_slice",
            "bytes_take",
            "bytes_drop",
            "bytes_zeros",
            "bytes_find",
            "bytes_starts_with",
            "bytes_ends_with",
        ],
        _ => &[],
    }
}

fn verify_bytes_file_write_plan_report_inner(
    report: &JsonValue,
    report_path: &Path,
    verify_negative_artifacts: bool,
) -> RuntimeResult<()> {
    for key in [
        "target_profile",
        "plan_hash",
        "plan_version",
        "capability_summary",
        "selected_step_ids",
        "state_summary",
        "semantic_delta_signatures",
        "semantic_deltas",
        "file_write_summary",
        "dynamic_path_file_write_summary",
        "plan_executor",
        "binary_path",
        "live_negative_case_count",
        "live_negative_cases",
        "fabricated_plan_negative_case_count",
        "fabricated_plan_negative_cases",
    ] {
        if report.get(key).is_none() {
            return Err(format!(
                "{} verify-bytes-file-write-plan report missing `{key}`",
                report_path.display()
            )
            .into());
        }
    }

    let source_plan = compile_report_machine_plan(report, report_path)?;
    let actual_plan_hash = boon_plan::plan_sha256(&source_plan).map_err(|error| {
        format!(
            "{} could not recompute source-derived MachinePlan hash: {error}",
            report_path.display()
        )
    })?;
    if report.get("plan_hash").and_then(JsonValue::as_str) != Some(actual_plan_hash.as_str()) {
        return Err(format!(
            "{} verify-bytes-file-write-plan plan_hash does not match source files and target_profile",
            report_path.display()
        )
        .into());
    }
    if report.get("program_hash") != report.get("source_hash") {
        return Err(format!(
            "{} verify-bytes-file-write-plan program_hash must match source_hash",
            report_path.display()
        )
        .into());
    }
    let expected_graph_node_count = compile_report_ir_graph_node_count(report, report_path)?;
    if report.get("graph_node_count").and_then(JsonValue::as_u64)
        != Some(expected_graph_node_count as u64)
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan graph_node_count does not match source-derived IR",
            report_path.display()
        )
        .into());
    }
    if report.get("plan_version") != Some(&serde_json::to_value(source_plan.version)?) {
        return Err(format!(
            "{} verify-bytes-file-write-plan plan_version does not match source-derived MachinePlan",
            report_path.display()
        )
        .into());
    }
    if report.get("capability_summary")
        != Some(&serde_json::to_value(&source_plan.capability_summary)?)
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan capability_summary does not match source-derived MachinePlan",
            report_path.display()
        )
        .into());
    }
    let verification = boon_plan::verify_plan(&source_plan).map_err(|error| {
        format!(
            "{} source-derived MachinePlan verification failed to run: {error}",
            report_path.display()
        )
    })?;
    if verification.status != "pass" || !source_plan.capability_summary.typed_lowering_executable {
        return Err(format!(
            "{} verify-bytes-file-write-plan requires a verified typed-lowering-executable MachinePlan",
            report_path.display()
        )
        .into());
    }
    let file_write_ops = source_plan
        .regions
        .iter()
        .flat_map(|region| region.ops.iter())
        .filter(|op| {
            matches!(
                op.kind,
                boon_plan::PlanOpKind::UpdateBranch {
                    expression_kind: boon_plan::PlanExpressionKind::FileWriteBytes,
                    ..
                }
            )
        })
        .collect::<Vec<_>>();
    let file_write_op_count = file_write_ops.len();
    if file_write_op_count != 1 {
        return Err(format!(
            "{} verify-bytes-file-write-plan expected exactly one FileWriteBytes op, found {file_write_op_count}",
            report_path.display()
        )
        .into());
    }
    let file_write_op = file_write_ops[0];
    let boon_plan::PlanOpKind::UpdateBranch { ordered_inputs, .. } = &file_write_op.kind else {
        unreachable!("file_write_op filter only returns update branches");
    };
    let [
        boon_plan::ValueRef::State(bytes_input_state),
        boon_plan::ValueRef::Constant(path_constant_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "{} verify-bytes-file-write-plan source FileWriteBytes op does not have bytes-state plus path-constant operands",
            report_path.display()
        )
        .into());
    };
    let plan_rel_path = source_plan
        .constants
        .iter()
        .find(|constant| constant.id == *path_constant_id)
        .and_then(|constant| match &constant.value {
            boon_plan::PlanConstantValue::Text { value } => Some(value.as_str()),
            _ => None,
        })
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-file-write-plan source FileWriteBytes path constant is missing or non-TEXT",
                report_path.display()
            )
        })?;
    if !file_read_path_is_safe_relative(plan_rel_path) {
        return Err(format!(
            "{} verify-bytes-file-write-plan source FileWriteBytes path is not safe relative",
            report_path.display()
        )
        .into());
    }
    let input_slot = source_plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == *bytes_input_state)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-file-write-plan input bytes state has no storage slot",
                report_path.display()
            )
        })?;
    if !matches!(
        input_slot.value_type,
        boon_plan::PlanValueType::Bytes { .. }
    ) {
        return Err(format!(
            "{} verify-bytes-file-write-plan input operand is not BYTES storage",
            report_path.display()
        )
        .into());
    }
    let Some(boon_plan::ValueRef::State(file_write_output_state)) = file_write_op.output else {
        return Err(format!(
            "{} verify-bytes-file-write-plan source FileWriteBytes op has no state output",
            report_path.display()
        )
        .into());
    };
    let output_slot = source_plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == file_write_output_state)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-file-write-plan output state has no storage slot",
                report_path.display()
            )
        })?;
    if !matches!(output_slot.value_type, boon_plan::PlanValueType::Text) {
        return Err(format!(
            "{} verify-bytes-file-write-plan output state is not TEXT storage",
            report_path.display()
        )
        .into());
    }

    let scenario_path = report
        .get("scenario_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing scenario_path", report_path.display()))?;
    let scenario = parse_scenario(Path::new(scenario_path))?;
    let source_path = report
        .get("source_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing source_path", report_path.display()))?;
    if scenario.source.as_deref() != Some(source_path) {
        return Err(format!(
            "{} verify-bytes-file-write-plan scenario source does not match report source_path",
            report_path.display()
        )
        .into());
    }
    let selected_step_ids = report
        .get("selected_step_ids")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} selected_step_ids is not an array",
                report_path.display()
            )
        })?;
    let selected_step_ids = selected_step_ids
        .iter()
        .map(|step| {
            step.as_str().map(str::to_owned).ok_or_else(|| {
                format!(
                    "{} selected_step_ids contains a non-string value",
                    report_path.display()
                )
                .into()
            })
        })
        .collect::<RuntimeResult<Vec<_>>>()?;
    if selected_step_ids != ["write-file-bytes".to_owned()] {
        return Err(format!(
            "{} verify-bytes-file-write-plan selected_step_ids changed",
            report_path.display()
        )
        .into());
    }
    let Some(step) = scenario
        .step
        .iter()
        .find(|step| step.id == "write-file-bytes")
    else {
        return Err(format!(
            "{} scenario is missing selected write step",
            report_path.display()
        )
        .into());
    };
    if step.expected_source_event.is_none() {
        return Err(format!(
            "{} selected write step has no expected_source_event",
            report_path.display()
        )
        .into());
    }
    if step
        .expected_source_event
        .as_ref()
        .and_then(|event| toml_string_ref(event, "source"))
        != Some("store.write")
    {
        return Err(format!(
            "{} selected write step expected_source_event.source is not store.write",
            report_path.display()
        )
        .into());
    }

    let summary = report
        .get("file_write_summary")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} file_write_summary is not an object",
                report_path.display()
            )
        })?;
    let rel_path = summary
        .get("path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} file_write_summary.path is not a string",
                report_path.display()
            )
        })?;
    if !file_read_path_is_safe_relative(rel_path) || rel_path != plan_rel_path {
        return Err(format!(
            "{} file_write_summary.path does not match source-derived safe FileWriteBytes path",
            report_path.display()
        )
        .into());
    }
    let host_root = summary
        .get("host_root")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} file_write_summary.host_root missing",
                report_path.display()
            )
        })?;
    let expected_host_root = Path::new(source_path)
        .parent()
        .map(|path| path.to_string_lossy().into_owned())
        .unwrap_or_default();
    if host_root != expected_host_root {
        return Err(format!(
            "{} file_write_summary.host_root does not match source parent directory",
            report_path.display()
        )
        .into());
    }
    let artifact_path = summary
        .get("artifact_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} file_write_summary.artifact_path missing",
                report_path.display()
            )
        })?;
    let expected_artifact_path = Path::new(host_root).join(rel_path);
    if expected_artifact_path != Path::new(artifact_path) {
        return Err(format!(
            "{} file_write_summary artifact_path does not match host_root/path",
            report_path.display()
        )
        .into());
    }
    let bytes = fs::read(artifact_path)?;
    let expected_len = bytes.len() as u64;
    let expected_sha = sha256_bytes(&bytes);
    let expected_first = bytes.first().copied().unwrap_or_default() as u64;
    let expected_last = bytes.last().copied().unwrap_or_default() as u64;
    if summary.get("byte_len").and_then(JsonValue::as_u64) != Some(expected_len)
        || summary.get("sha256").and_then(JsonValue::as_str) != Some(expected_sha.as_str())
        || summary.get("first_byte").and_then(JsonValue::as_u64) != Some(expected_first)
        || summary.get("last_byte").and_then(JsonValue::as_u64) != Some(expected_last)
        || summary.get("status").and_then(JsonValue::as_str) != Some("pass")
        || summary.get("mode").and_then(JsonValue::as_str)
            != Some("typed-machine-plan-host-file-write-v1")
        || summary.get("expression_kind").and_then(JsonValue::as_str) != Some("file_write_bytes")
        || summary.get("write_mode").and_then(JsonValue::as_str) != Some("create_or_truncate")
        || summary
            .get("verified_after_write")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || summary
            .get("public_inline_bytes_absent")
            .and_then(JsonValue::as_bool)
            != Some(true)
    {
        return Err(format!(
            "{} file_write_summary does not match artifact bytes",
            report_path.display()
        )
        .into());
    }

    verify_dynamic_path_file_write_summary(report, report_path)?;

    if json_contains_key(report, "inline_bytes") {
        return Err(format!(
            "{} verify-bytes-file-write-plan must not expose inline byte payloads",
            report_path.display()
        )
        .into());
    }
    if report.get("legacy_comparison").is_some() {
        return Err(format!(
            "{} verify-bytes-file-write-plan must not emit legacy_comparison",
            report_path.display()
        )
        .into());
    }
    let executor = report
        .get("plan_executor")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} plan_executor is not an object", report_path.display()))?;
    if executor.get("executor").and_then(JsonValue::as_str)
        != Some("cpu-plan-root-list-scenario-v1")
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan executor is not cpu-plan-root-list-scenario-v1",
            report_path.display()
        )
        .into());
    }
    for key in [
        "runtime_ast_eval_count",
        "executable_string_path_count",
        "unknown_plan_op_count",
        "graph_rebuild_count",
        "graph_clones_per_item",
    ] {
        if executor.get(key).and_then(JsonValue::as_u64) != Some(0) {
            return Err(format!(
                "{} verify-bytes-file-write-plan plan_executor.{key} must be zero",
                report_path.display()
            )
            .into());
        }
    }
    if executor
        .get("selected_step_count")
        .and_then(JsonValue::as_u64)
        != Some(1)
        || executor
            .get("executed_update_branch_count")
            .and_then(JsonValue::as_u64)
            != Some(1)
        || executor.get("state_summary") != report.get("state_summary")
        || executor.get("semantic_delta_signatures") != report.get("semantic_delta_signatures")
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan executor summary does not match report",
            report_path.display()
        )
        .into());
    }
    let per_step = executor
        .get("per_step")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} plan_executor.per_step is not an array",
                report_path.display()
            )
        })?;
    if per_step.len() != 1 {
        return Err(format!(
            "{} verify-bytes-file-write-plan expected one executor step",
            report_path.display()
        )
        .into());
    }
    let write_update = report
        .pointer("/plan_executor/per_step/0/updates/0")
        .ok_or_else(|| format!("{} missing file-write update", report_path.display()))?;
    let host_effect = write_update
        .get("host_effect")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| format!("{} missing file-write host_effect", report_path.display()))?;
    let output_label = plan_state_label(&source_plan, file_write_output_state.0);
    if write_update
        .get("expression_kind")
        .and_then(JsonValue::as_str)
        != Some("file_write_bytes")
        || per_step[0].get("step_id").and_then(JsonValue::as_str) != Some("write-file-bytes")
        || per_step[0].get("source").and_then(JsonValue::as_str) != Some("store.write")
        || per_step[0].get("source_id").and_then(JsonValue::as_u64)
            != plan_source_id_for_label(&source_plan, "store.write").map(|id| id as u64)
        || write_update.get("source_id").and_then(JsonValue::as_u64)
            != plan_source_id_for_label(&source_plan, "store.write").map(|id| id as u64)
        || write_update.get("update_op_id").and_then(JsonValue::as_u64)
            != Some(file_write_op.id.0 as u64)
        || write_update
            .get("candidate_update_op_ids")
            .and_then(JsonValue::as_array)
            != Some(&vec![json!(file_write_op.id.0)])
        || write_update.get("target_state").and_then(JsonValue::as_str)
            != Some(output_label.as_str())
        || write_update
            .pointer("/update_constant_value/path")
            .and_then(JsonValue::as_str)
            != Some(rel_path)
        || write_update.get("value").and_then(JsonValue::as_str) != Some(rel_path)
        || report
            .pointer(&format!(
                "/state_summary/{}",
                output_label.replace('~', "~0").replace('/', "~1")
            ))
            .and_then(JsonValue::as_str)
            != Some(rel_path)
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan file-write update does not match source plan",
            report_path.display()
        )
        .into());
    }
    if write_update
        .pointer("/bytes_access/read_only")
        .and_then(JsonValue::as_bool)
        != Some(true)
        || write_update
            .pointer("/bytes_access/access_source")
            .and_then(JsonValue::as_str)
            != Some("root_bytes_state")
        || write_update
            .pointer("/bytes_access/cow_kind")
            .and_then(JsonValue::as_str)
            != Some("borrowed")
        || write_update
            .pointer("/bytes_access/host_boundary")
            .and_then(JsonValue::as_str)
            != Some("file_write_bytes")
        || write_update
            .pointer("/bytes_access/byte_len")
            .and_then(JsonValue::as_u64)
            != Some(expected_len)
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan file-write update did not prove explicit BYTES access for host boundary",
            report_path.display()
        )
        .into());
    }
    if executor
        .get("bytes_storage_no_copy")
        .and_then(JsonValue::as_bool)
        != Some(true)
        || [
            "copy_from_slice_bytes",
            "vec_clone_bytes",
            "vec_alloc_bytes",
            "zero_fill_bytes",
        ]
        .iter()
        .any(|key| {
            executor
                .get("bytes_storage_counters")
                .and_then(|counters| counters.get(*key))
                .and_then(JsonValue::as_u64)
                != Some(0)
        })
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan file-write path did not prove zero runtime BYTES storage copy counters",
            report_path.display()
        )
        .into());
    }
    let host_artifact_path = host_effect
        .get("artifact_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} host_effect.artifact_path missing",
                report_path.display()
            )
        })?;
    let canonical_artifact = Path::new(artifact_path).canonicalize()?;
    let canonical_host_artifact = Path::new(host_artifact_path).canonicalize()?;
    if host_effect.get("kind").and_then(JsonValue::as_str) != Some("file_write_bytes")
        || host_effect.get("status").and_then(JsonValue::as_str) != Some("pass")
        || host_effect.get("mode").and_then(JsonValue::as_str)
            != Some("typed-machine-plan-host-file-write-v1")
        || host_effect.get("path").and_then(JsonValue::as_str) != Some(rel_path)
        || canonical_host_artifact != canonical_artifact
        || host_effect.get("byte_len").and_then(JsonValue::as_u64) != Some(expected_len)
        || host_effect.get("sha256").and_then(JsonValue::as_str) != Some(expected_sha.as_str())
        || host_effect.get("first_byte").and_then(JsonValue::as_u64) != Some(expected_first)
        || host_effect.get("last_byte").and_then(JsonValue::as_u64) != Some(expected_last)
        || host_effect.get("write_mode").and_then(JsonValue::as_str) != Some("create_or_truncate")
        || host_effect
            .get("verified_after_write")
            .and_then(JsonValue::as_bool)
            != Some(true)
    {
        return Err(format!(
            "{} verify-bytes-file-write-plan host_effect does not match artifact bytes",
            report_path.display()
        )
        .into());
    }
    let flattened_semantic_deltas = per_step
        .iter()
        .flat_map(|step| {
            step.get("semantic_deltas")
                .and_then(JsonValue::as_array)
                .into_iter()
                .flatten()
                .cloned()
        })
        .collect::<Vec<_>>();
    if report.get("semantic_deltas") != Some(&JsonValue::Array(flattened_semantic_deltas)) {
        return Err(format!(
            "{} verify-bytes-file-write-plan semantic_deltas do not match executor per-step deltas",
            report_path.display()
        )
        .into());
    }
    let checks = report
        .get("per_step_pass_fail")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-bytes-file-write-plan per_step_pass_fail is missing",
                report_path.display()
            )
        })?;
    verify_bytes_file_write_live_negative_evidence(report, report_path, checks)?;
    verify_bytes_file_write_fabricated_plan_negative_evidence(
        report,
        report_path,
        checks,
        &source_plan,
    )?;
    verify_bytes_file_write_negative_evidence(report, report_path, verify_negative_artifacts)?;
    Ok(())
}

struct ExpectedBytesFileWriteLiveNegativeCase {
    id: &'static str,
    category: &'static str,
    stage: &'static str,
    expected_error_contains: &'static str,
    target_kind: Option<&'static str>,
}

fn verify_dynamic_path_file_write_summary(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<()> {
    let summary = report
        .get("dynamic_path_file_write_summary")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} dynamic_path_file_write_summary is not an object",
                report_path.display()
            )
        })?;
    let source_path = summary
        .get("source_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} dynamic_path_file_write_summary.source_path missing",
                report_path.display()
            )
        })?;
    let scenario_path = summary
        .get("scenario_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| {
            format!(
                "{} dynamic_path_file_write_summary.scenario_path missing",
                report_path.display()
            )
        })?;
    let source = fs::read_to_string(source_path)?;
    let parsed = boon_parser::parse_source(source_path.to_owned(), source)?;
    let ir = boon_ir::lower(&parsed).map_err(|error| {
        format!(
            "{} could not lower dynamic-path File/write_bytes source: {error}",
            report_path.display()
        )
    })?;
    boon_ir::verify_hidden_identity(&ir)?;
    boon_ir::verify_static_schedule(&ir)?;
    let plan =
        boon_compiler::compile_typed_program(&ir, boon_plan::TargetProfile::SoftwareDefault)?;
    let plan_hash = boon_plan::plan_sha256(&plan)?;
    if summary.get("plan_hash").and_then(JsonValue::as_str) != Some(plan_hash.as_str()) {
        return Err(format!(
            "{} dynamic-path File/write_bytes plan_hash does not match source",
            report_path.display()
        )
        .into());
    }
    let verification = boon_plan::verify_plan(&plan)?;
    if verification.status != "pass" || !plan.capability_summary.typed_lowering_executable {
        return Err(format!(
            "{} dynamic-path File/write_bytes MachinePlan is not verified typed executable",
            report_path.display()
        )
        .into());
    }
    let file_write_ops = plan
        .regions
        .iter()
        .flat_map(|region| region.ops.iter())
        .filter(|op| {
            matches!(
                op.kind,
                boon_plan::PlanOpKind::UpdateBranch {
                    expression_kind: boon_plan::PlanExpressionKind::FileWriteBytes,
                    ..
                }
            )
        })
        .collect::<Vec<_>>();
    if file_write_ops.len() != 1 {
        return Err(format!(
            "{} dynamic-path File/write_bytes expected exactly one op, found {}",
            report_path.display(),
            file_write_ops.len()
        )
        .into());
    }
    let op = file_write_ops[0];
    let boon_plan::PlanOpKind::UpdateBranch { ordered_inputs, .. } = &op.kind else {
        unreachable!("FileWriteBytes op filter only returns update branches");
    };
    let [
        boon_plan::ValueRef::State(bytes_state_id),
        boon_plan::ValueRef::State(path_state_id),
    ] = ordered_inputs.as_slice()
    else {
        return Err(format!(
            "{} dynamic-path File/write_bytes op does not use [State(bytes), State(path)] operands",
            report_path.display()
        )
        .into());
    };
    let bytes_slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == *bytes_state_id)
        .ok_or_else(|| "dynamic-path File/write_bytes missing bytes input slot".to_owned())?;
    let path_slot = plan
        .storage_layout
        .scalar_slots
        .iter()
        .find(|slot| slot.state_id == *path_state_id)
        .ok_or_else(|| "dynamic-path File/write_bytes missing path input slot".to_owned())?;
    if !matches!(
        bytes_slot.value_type,
        boon_plan::PlanValueType::Bytes { .. }
    ) || !matches!(path_slot.value_type, boon_plan::PlanValueType::Text)
    {
        return Err(format!(
            "{} dynamic-path File/write_bytes operands are not BYTES plus TEXT state",
            report_path.display()
        )
        .into());
    }
    let path_state_label = plan_state_label(&plan, path_state_id.0);
    if summary.get("path_operand").and_then(JsonValue::as_str) != Some("state")
        || summary.get("path_state").and_then(JsonValue::as_str) != Some(path_state_label.as_str())
    {
        return Err(format!(
            "{} dynamic-path File/write_bytes summary does not identify the path state",
            report_path.display()
        )
        .into());
    }
    let rel_path = summary
        .get("path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| "dynamic-path File/write_bytes summary missing path".to_owned())?;
    if !file_read_path_is_safe_relative(rel_path) {
        return Err(format!(
            "{} dynamic-path File/write_bytes path is not safe relative",
            report_path.display()
        )
        .into());
    }
    let scenario = parse_scenario(Path::new(scenario_path))?;
    if scenario.source.as_deref() != Some(source_path) {
        return Err(format!(
            "{} dynamic-path File/write_bytes scenario source mismatch",
            report_path.display()
        )
        .into());
    }
    if summary
        .get("selected_step_ids")
        .and_then(JsonValue::as_array)
        .map(|steps| {
            steps
                .iter()
                .filter_map(JsonValue::as_str)
                .collect::<Vec<_>>()
        })
        != Some(vec!["write-file-bytes-dynamic-path"])
    {
        return Err(format!(
            "{} dynamic-path File/write_bytes selected_step_ids changed",
            report_path.display()
        )
        .into());
    }
    let artifact_path = summary
        .get("artifact_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| "dynamic-path File/write_bytes summary missing artifact_path".to_owned())?;
    let bytes = fs::read(artifact_path)?;
    let expected_len = bytes.len() as u64;
    let expected_sha = sha256_bytes(&bytes);
    if summary.get("byte_len").and_then(JsonValue::as_u64) != Some(expected_len)
        || summary.get("sha256").and_then(JsonValue::as_str) != Some(expected_sha.as_str())
        || summary.get("status").and_then(JsonValue::as_str) != Some("pass")
        || summary.get("mode").and_then(JsonValue::as_str)
            != Some("typed-machine-plan-host-file-write-v1")
        || summary.get("expression_kind").and_then(JsonValue::as_str) != Some("file_write_bytes")
        || summary.get("write_mode").and_then(JsonValue::as_str) != Some("create_or_truncate")
        || summary
            .get("verified_after_write")
            .and_then(JsonValue::as_bool)
            != Some(true)
        || summary
            .get("public_inline_bytes_absent")
            .and_then(JsonValue::as_bool)
            != Some(true)
    {
        return Err(format!(
            "{} dynamic-path File/write_bytes summary does not match artifact bytes",
            report_path.display()
        )
        .into());
    }
    let executor = summary
        .get("plan_executor")
        .and_then(JsonValue::as_object)
        .ok_or_else(|| {
            format!(
                "{} dynamic-path File/write_bytes plan_executor is not an object",
                report_path.display()
            )
        })?;
    for key in [
        "runtime_ast_eval_count",
        "executable_string_path_count",
        "unknown_plan_op_count",
        "graph_rebuild_count",
        "graph_clones_per_item",
    ] {
        if executor.get(key).and_then(JsonValue::as_u64) != Some(0) {
            return Err(format!(
                "{} dynamic-path File/write_bytes plan_executor.{key} must be zero",
                report_path.display()
            )
            .into());
        }
    }
    let update = summary
        .get("plan_executor")
        .unwrap_or(&JsonValue::Null)
        .pointer("/per_step/0/updates/0")
        .ok_or_else(|| {
            format!(
                "{} dynamic-path File/write_bytes missing executor update",
                report_path.display()
            )
        })?;
    if update.get("expression_kind").and_then(JsonValue::as_str) != Some("file_write_bytes")
        || update
            .pointer("/update_constant_value/path")
            .and_then(JsonValue::as_str)
            != Some(rel_path)
        || update
            .pointer("/update_constant_value/path_state")
            .and_then(JsonValue::as_str)
            != Some(path_state_label.as_str())
        || update
            .pointer("/bytes_access/path_source")
            .and_then(JsonValue::as_str)
            != Some("state")
        || update
            .pointer("/bytes_access/host_boundary")
            .and_then(JsonValue::as_str)
            != Some("file_write_bytes")
        || update
            .pointer("/host_effect/sha256")
            .and_then(JsonValue::as_str)
            != Some(expected_sha.as_str())
        || update
            .pointer("/host_effect/byte_len")
            .and_then(JsonValue::as_u64)
            != Some(expected_len)
    {
        return Err(format!(
            "{} dynamic-path File/write_bytes executor update does not prove state-sourced host write",
            report_path.display()
        )
        .into());
    }
    if json_contains_key(
        summary.get("plan_executor").unwrap_or(&JsonValue::Null),
        "inline_bytes",
    ) {
        return Err(format!(
            "{} dynamic-path File/write_bytes proof leaked inline byte payloads",
            report_path.display()
        )
        .into());
    }
    Ok(())
}

