fn local_field_name(label: &str) -> String {
    label
        .rsplit_once('.')
        .map(|(_, local)| local.to_owned())
        .unwrap_or_else(|| label.to_owned())
}

fn row_scoped_source_routes<'a>(
    plan: &'a boon_plan::MachinePlan,
    list_slot: &boon_plan::ListStorageSlot,
) -> Vec<&'a boon_plan::SourceRoute> {
    let mut routes = plan
        .source_routes
        .iter()
        .filter(|route| route.scoped && route.scope_id == list_slot.scope_id)
        .collect::<Vec<_>>();
    routes.sort_by_key(|route| route.source_id.0);
    routes
}

fn plan_json_delta_signature(delta: &JsonValue, report_path: &Path) -> RuntimeResult<String> {
    let kind = delta
        .get("kind")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} semantic delta has no kind", report_path.display()))?;
    Ok(match delta.get("field_path").and_then(JsonValue::as_str) {
        Some(field_path) => format!("{kind}:{field_path}"),
        None => kind.to_owned(),
    })
}

fn debug_entry_numeric_id(value: &str, prefix: &str) -> Option<usize> {
    value
        .strip_prefix(prefix)
        .and_then(|suffix| suffix.strip_prefix(':'))
        .and_then(|suffix| suffix.parse::<usize>().ok())
}

fn source_event_payload_value(
    source_event: &serde_json::Map<String, JsonValue>,
    field: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<JsonValue> {
    match field {
        JsonValue::String(name) if name == "Text" => source_event
            .get("text")
            .filter(|value| !value.is_null())
            .cloned()
            .ok_or_else(|| {
                format!(
                    "{} source_event is missing text payload",
                    report_path.display()
                )
                .into()
            }),
        JsonValue::String(name) if name == "Key" => source_event
            .get("key")
            .filter(|value| !value.is_null())
            .cloned()
            .ok_or_else(|| {
                format!(
                    "{} source_event is missing key payload",
                    report_path.display()
                )
                .into()
            }),
        JsonValue::String(name) if name == "Address" => source_event
            .get("address")
            .filter(|value| !value.is_null())
            .cloned()
            .ok_or_else(|| {
                format!(
                    "{} source_event is missing address payload",
                    report_path.display()
                )
                .into()
            }),
        JsonValue::String(name) if name == "Bytes" => {
            let bytes = source_event_payload_bytes(source_event, report_path)?;
            Ok(expected_dynamic_bytes_summary(&bytes))
        }
        JsonValue::Object(object) => {
            let name = object
                .get("Named")
                .and_then(JsonValue::as_str)
                .ok_or_else(|| {
                    format!(
                        "{} source_payload_field object is not a Named field",
                        report_path.display()
                    )
                })?;
            source_event
                .get("payload")
                .and_then(JsonValue::as_object)
                .and_then(|payload| payload.get(name))
                .cloned()
                .ok_or_else(|| {
                    format!(
                        "{} source_event.payload is missing `{name}`",
                        report_path.display()
                    )
                    .into()
                })
        }
        _ => Err(format!(
            "{} source_payload_field has unsupported JSON shape",
            report_path.display()
        )
        .into()),
    }
}

fn compile_report_machine_plan(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<boon_plan::MachinePlan> {
    let target = report
        .get("target_profile")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing target_profile", report_path.display()))?;
    let target_profile = boon_plan::TargetProfile::from_name(target).map_err(|error| {
        format!(
            "{} invalid target_profile `{target}`: {error}",
            report_path.display()
        )
    })?;
    let parsed = parse_report_program(report, report_path)?;
    let ir = boon_ir::lower(&parsed).map_err(|error| {
        format!(
            "{} could not lower report source files: {error}",
            report_path.display()
        )
    })?;
    boon_ir::verify_hidden_identity(&ir).map_err(|error| {
        format!(
            "{} source-derived IR failed hidden identity verification: {error}",
            report_path.display()
        )
    })?;
    boon_ir::verify_static_schedule(&ir).map_err(|error| {
        format!(
            "{} source-derived IR failed static schedule verification: {error}",
            report_path.display()
        )
    })?;
    boon_compiler::compile_typed_program(&ir, target_profile).map_err(|error| {
        format!(
            "{} could not compile source-derived MachinePlan: {error}",
            report_path.display()
        )
        .into()
    })
}

fn compile_report_resolved_constant_table(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<JsonValue> {
    let parsed = parse_report_program(report, report_path)?;
    let ir = boon_ir::lower(&parsed).map_err(|error| {
        format!(
            "{} could not lower report source files for resolved constants: {error}",
            report_path.display()
        )
    })?;
    serde_json::to_value(&ir.typecheck_report.resolved_constant_table).map_err(|error| {
        format!(
            "{} could not serialize source-derived resolved_constant_table: {error}",
            report_path.display()
        )
        .into()
    })
}

fn compile_report_ir_graph_node_count(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<usize> {
    let parsed = parse_report_program(report, report_path)?;
    let ir = boon_ir::lower(&parsed).map_err(|error| {
        format!(
            "{} could not lower report source files for graph_node_count: {error}",
            report_path.display()
        )
    })?;
    Ok(ir.graph_node_count)
}

struct ReportSourceUnit {
    path: String,
    source: String,
    start_line: usize,
}

fn parse_report_program(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<boon_parser::ParsedProgram> {
    let source_path = report
        .get("source_path")
        .and_then(JsonValue::as_str)
        .ok_or_else(|| format!("{} missing source_path", report_path.display()))?;
    let mut units = report_source_units(report, report_path)?;
    if units.is_empty() {
        let source = fs::read_to_string(source_path)?;
        return Ok(boon_parser::parse_source(source_path.to_owned(), source)?);
    }
    if units.len() == 1 {
        if units[0].path != source_path {
            return Err(format!(
                "{} single-file source_files path `{}` does not match source_path `{source_path}`",
                report_path.display(),
                units[0].path
            )
            .into());
        }
        let unit = units.remove(0);
        return Ok(boon_parser::parse_source(
            source_path.to_owned(),
            unit.source,
        )?);
    }
    units.sort_by(|left, right| {
        left.start_line
            .cmp(&right.start_line)
            .then_with(|| left.path.cmp(&right.path))
    });
    Ok(boon_parser::parse_project(
        source_path.to_owned(),
        units.into_iter().map(|unit| (unit.path, unit.source)),
    )?)
}

fn report_source_units(
    report: &JsonValue,
    report_path: &Path,
) -> RuntimeResult<Vec<ReportSourceUnit>> {
    let Some(source_files) = report.get("source_files").and_then(JsonValue::as_array) else {
        return Ok(Vec::new());
    };
    let mut units = Vec::new();
    for (index, file) in source_files.iter().enumerate() {
        if let Some(path) = file.as_str() {
            units.push(ReportSourceUnit {
                path: path.to_owned(),
                source: fs::read_to_string(path)?,
                start_line: index + 1,
            });
            continue;
        }
        let object = file.as_object().ok_or_else(|| {
            format!(
                "{} source_files[{index}] is neither a path string nor an object",
                report_path.display()
            )
        })?;
        let path = object
            .get("path")
            .and_then(JsonValue::as_str)
            .ok_or_else(|| {
                format!(
                    "{} source_files[{index}].path is not a string",
                    report_path.display()
                )
            })?;
        let start_line = object
            .get("start_line")
            .and_then(JsonValue::as_u64)
            .ok_or_else(|| {
                format!(
                    "{} source_files[{index}].start_line is not a number",
                    report_path.display()
                )
            })?;
        units.push(ReportSourceUnit {
            path: path.to_owned(),
            source: fs::read_to_string(path)?,
            start_line: start_line as usize,
        });
    }
    Ok(units)
}

fn expected_initial_state_summary(
    plan: &boon_plan::MachinePlan,
    report_path: &Path,
) -> RuntimeResult<JsonValue> {
    let mut state_summary = serde_json::Map::new();
    let mut initialized_state_count = 0usize;
    let mut source_route_count = 0usize;
    for region in &plan.regions {
        match region.kind {
            boon_plan::RegionKind::SourceRouting => {
                for op in &region.ops {
                    if !matches!(op.kind, boon_plan::PlanOpKind::SourceRoute)
                        || !matches!(op.output, Some(boon_plan::ValueRef::Source(_)))
                    {
                        return Err(format!(
                            "{} run-plan source-routing region contains unsupported op",
                            report_path.display()
                        )
                        .into());
                    }
                    source_route_count += 1;
                }
            }
            boon_plan::RegionKind::StateInitialization => {
                for op in &region.ops {
                    let boon_plan::PlanOpKind::StateInitialize {
                        initial_value_kind,
                        initial_constant_id,
                    } = op.kind
                    else {
                        return Err(format!(
                            "{} run-plan state-initialization region contains unsupported op",
                            report_path.display()
                        )
                        .into());
                    };
                    let Some(boon_plan::ValueRef::State(state_id)) = op.output else {
                        return Err(format!(
                            "{} run-plan StateInitialize op is missing typed state output",
                            report_path.display()
                        )
                        .into());
                    };
                    let slot = plan
                        .storage_layout
                        .scalar_slots
                        .iter()
                        .find(|slot| slot.state_id == state_id)
                        .ok_or_else(|| {
                            format!(
                                "{} run-plan StateInitialize targets missing state {}",
                                report_path.display(),
                                state_id.0
                            )
                        })?;
                    if slot.initial_value_kind != initial_value_kind
                        || slot.initial_constant_id != initial_constant_id
                    {
                        return Err(format!(
                            "{} run-plan StateInitialize op and storage slot disagree for state {}",
                            report_path.display(),
                            state_id.0
                        )
                        .into());
                    }
                    if !slot.indexed {
                        let value = expected_initial_value(
                            plan,
                            slot.initial_constant_id,
                            &slot.value_type,
                            slot.initial_value_kind,
                            report_path,
                        )?;
                        state_summary.insert(plan_state_label(plan, state_id.0), value);
                    }
                    initialized_state_count += 1;
                }
            }
            boon_plan::RegionKind::DerivedEvaluation => {
                for op in &region.ops {
                    match &op.kind {
                        boon_plan::PlanOpKind::DerivedValue { .. }
                            if op.unresolved_executable_ref_count == 0 => {}
                        _ => {
                            return Err(format!(
                                "{} run-plan schema does not accept DerivedEvaluation op {} in initial-state proof reports",
                                report_path.display(),
                                op.id.0
                            )
                            .into());
                        }
                    }
                }
            }
            boon_plan::RegionKind::UpdateBranches
            | boon_plan::RegionKind::ListProjections
            | boon_plan::RegionKind::DependencyEdges => {}
            boon_plan::RegionKind::ListOperations => {
                for op in &region.ops {
                    match &op.kind {
                        boon_plan::PlanOpKind::ListOperation { .. }
                            if op.unresolved_executable_ref_count == 0 => {}
                        _ => {
                            return Err(format!(
                                "{} run-plan schema does not accept {:?} op {} in initial-state proof reports",
                                report_path.display(),
                                region.kind,
                                op.id.0
                            )
                            .into());
                        }
                    }
                }
            }
        }
    }
    if initialized_state_count != plan.storage_layout.scalar_slots.len() {
        return Err(format!(
            "{} run-plan initialized {initialized_state_count} state(s), expected {}",
            report_path.display(),
            plan.storage_layout.scalar_slots.len()
        )
        .into());
    }
    if source_route_count != plan.source_routes.len() {
        return Err(format!(
            "{} run-plan saw {source_route_count} source route op(s), expected {}",
            report_path.display(),
            plan.source_routes.len()
        )
        .into());
    }
    Ok(JsonValue::Object(state_summary))
}

fn expected_initial_value(
    plan: &boon_plan::MachinePlan,
    constant_id: Option<boon_plan::PlanConstantId>,
    value_type: &boon_plan::PlanValueType,
    initial_value_kind: boon_plan::InitialValueKind,
    report_path: &Path,
) -> RuntimeResult<JsonValue> {
    let constant_id = constant_id.ok_or_else(|| {
        format!(
            "{} run-plan state initializer is missing a typed constant id",
            report_path.display()
        )
    })?;
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "{} run-plan missing plan constant {}",
                report_path.display(),
                constant_id.0
            )
        })?;
    match (&constant.value, value_type, initial_value_kind) {
        (
            boon_plan::PlanConstantValue::Text { value },
            boon_plan::PlanValueType::Text,
            boon_plan::InitialValueKind::Text,
        ) => Ok(json!(value)),
        (
            boon_plan::PlanConstantValue::Number { value },
            boon_plan::PlanValueType::Number,
            boon_plan::InitialValueKind::Number,
        ) => Ok(json!(value)),
        (
            boon_plan::PlanConstantValue::Byte { value },
            boon_plan::PlanValueType::Byte,
            boon_plan::InitialValueKind::Byte,
        ) => Ok(json!(value)),
        (
            boon_plan::PlanConstantValue::Bool { value },
            boon_plan::PlanValueType::Bool,
            boon_plan::InitialValueKind::Bool,
        ) => Ok(json!(value)),
        (
            boon_plan::PlanConstantValue::Enum { value },
            boon_plan::PlanValueType::Enum,
            boon_plan::InitialValueKind::Enum,
        ) => Ok(json!(value)),
        (
            boon_plan::PlanConstantValue::Bytes {
                byte_len,
                sha256,
                inline_bytes: Some(_),
            },
            boon_plan::PlanValueType::Bytes { fixed_len },
            boon_plan::InitialValueKind::Bytes,
        ) => {
            if let Some(expected_len) = *fixed_len {
                if expected_len != *byte_len {
                    return Err(format!(
                        "{} run-plan bytes constant {} has byte_len {byte_len} but storage fixed_len {expected_len}",
                        report_path.display(),
                        constant_id.0
                    )
                    .into());
                }
            }
            Ok(json!({
                "$boon_type": "BYTES",
                "storage": "inline",
                "digest": sha256,
                "byte_len": byte_len
            }))
        }
        (
            boon_plan::PlanConstantValue::Bytes {
                inline_bytes: None, ..
            },
            boon_plan::PlanValueType::Bytes { .. },
            boon_plan::InitialValueKind::Bytes,
        ) => Err(format!(
            "{} run-plan bytes constant {} has no executable payload",
            report_path.display(),
            constant_id.0
        )
        .into()),
        _ => Err(format!(
            "{} run-plan constant {} does not match scalar storage type {:?}/{:?}",
            report_path.display(),
            constant_id.0,
            value_type,
            initial_value_kind
        )
        .into()),
    }
}

fn expected_initial_inline_bytes(
    plan: &boon_plan::MachinePlan,
    slot: &boon_plan::ScalarStorageSlot,
    report_path: &Path,
) -> RuntimeResult<Vec<u8>> {
    let constant_id = slot.initial_constant_id.ok_or_else(|| {
        format!(
            "{} bytes state `{}` has no typed initial constant",
            report_path.display(),
            plan_state_label(plan, slot.state_id.0)
        )
    })?;
    let constant = plan
        .constants
        .iter()
        .find(|constant| constant.id == constant_id)
        .ok_or_else(|| {
            format!(
                "{} missing plan constant {}",
                report_path.display(),
                constant_id.0
            )
        })?;
    let boon_plan::PlanConstantValue::Bytes {
        byte_len,
        sha256,
        inline_bytes: Some(bytes),
    } = &constant.value
    else {
        return Err(format!(
            "{} bytes state `{}` is not backed by an inline byte constant",
            report_path.display(),
            plan_state_label(plan, slot.state_id.0)
        )
        .into());
    };
    if let boon_plan::PlanValueType::Bytes {
        fixed_len: Some(expected_len),
    } = &slot.value_type
        && *expected_len != *byte_len
    {
        return Err(format!(
            "{} bytes state `{}` has byte_len {byte_len} but storage fixed_len {expected_len}",
            report_path.display(),
            plan_state_label(plan, slot.state_id.0)
        )
        .into());
    }
    if sha256_bytes(bytes) != *sha256 || bytes.len() as u64 != *byte_len {
        return Err(format!(
            "{} bytes state `{}` initial payload does not match typed digest/length",
            report_path.display(),
            plan_state_label(plan, slot.state_id.0)
        )
        .into());
    }
    Ok(bytes.clone())
}

fn plan_state_label(plan: &boon_plan::MachinePlan, state_id: usize) -> String {
    let expected = format!("state:{state_id}");
    plan.debug_map
        .state_slots
        .iter()
        .find(|entry| entry.id == expected)
        .map(|entry| entry.label.clone())
        .unwrap_or(expected)
}

fn is_sha256_hex(value: &str) -> bool {
    value.len() == 64 && value.bytes().all(|byte| byte.is_ascii_hexdigit())
}

fn report_is_native_gpu_command(report: &JsonValue) -> bool {
    let Some(command) = report.get("command").and_then(JsonValue::as_str) else {
        return false;
    };
    command.starts_with("verify-native-gpu-")
        || matches!(
            command,
            "boon-native-playground-role"
                | "verify-demand-driven-render-loop"
                | "verify-native-dev-editor-scroll-speed"
                | "verify-native-example-switch-speed"
                | "verify-native-real-window-input-environment"
                | "verify-native-dev-window-editor"
                | "verify-native-example-tabs"
                | "verify-native-editor-format"
                | "verify-native-example-speed"
                | "verify-native-product-render-graph"
                | "verify-native-todomvc-reference-parity"
                | "verify-native-todomvc-physical-reference-parity"
                | "verify-native-todomvc-input-parity"
                | "verify-native-counter-interaction-speed"
                | "verify-native-cells-visible-click-e2e"
        )
}

fn report_is_native_ux_command(report: &JsonValue) -> bool {
    let Some(command) = report.get("command").and_then(JsonValue::as_str) else {
        return false;
    };
    command.ends_with("-speed")
        || command.contains("interaction-speed")
        || matches!(
            command,
            "verify-native-gpu-preview-e2e"
                | "verify-native-gpu-idle-wake"
                | "verify-native-cells-visible-click-e2e"
                | "verify-demand-driven-render-loop"
        )
}

fn verify_native_gpu_report_contract(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let mut reasons = Vec::new();
    if report_is_native_ux_command(report)
        && report.get("render_loop_mode").and_then(JsonValue::as_str) == Some("continuous_probe")
    {
        reasons.push("native UX reports must not use render_loop_mode=continuous_probe".to_owned());
    }
    if report_is_native_ux_command(report) {
        let passive_scroll = report_is_native_passive_scroll_command(report);
        collect_native_ux_product_path_reasons(report, "$", passive_scroll, &mut reasons);
        collect_native_ux_proof_currentness_reasons(report, &mut reasons);
    }
    if let Some(frame_pacing) = report.get("frame_pacing") {
        verify_native_frame_pacing(frame_pacing, "$.frame_pacing", &mut reasons);
    }
    if let Some(preview_perf) = report.get("preview_perf_stats") {
        verify_native_preview_perf_stats(preview_perf, "$.preview_perf_stats", &mut reasons);
    }
    collect_native_frame_evidence_reasons(report, "$", &mut reasons);
    collect_native_top_level_frame_evidence_linkage_reasons(report, &mut reasons);
    if reasons.is_empty() {
        Ok(())
    } else {
        Err(format!(
            "{} native GPU report contract failed: {}",
            report_path.display(),
            reasons.join("; ")
        )
        .into())
    }
}

fn native_gpu_product_path_negative_case_ids() -> &'static [&'static str] {
    &[
        "continuous-probe-ux-report",
        "proof-required-visible-update",
        "below-host-input-injection",
        "preview-blocked-on-ipc-product-path",
        "passive-scroll-runtime-dispatch",
        "passive-scroll-graph-rebuild",
        "dev-perf-row-hot-path-query",
        "desktop-screenshot-visible-proof",
        "nested-private-runtime-dispatch",
        "browser-proof-substituted-for-native",
        "cosmic-toplevel-proof",
        "lagged-ux-proof",
        "pending-ux-readback",
        "same-frame-proof-identity-mismatch",
        "render-hook-offscreen-proof-hot-path",
    ]
}

fn verify_native_gpu_negative_report(report: &JsonValue, report_path: &Path) -> RuntimeResult<()> {
    let required_ids = report
        .get("required_negative_cases")
        .and_then(JsonValue::as_array)
        .ok_or_else(|| {
            format!(
                "{} verify-native-gpu-negative required_negative_cases is missing",
                report_path.display()
            )
        })?
        .iter()
        .map(|value| {
            value.as_str().ok_or_else(|| {
                format!(
                    "{} verify-native-gpu-negative required_negative_cases contains a non-string id",
                    report_path.display()
                )
            })
        })
        .collect::<Result<Vec<_>, _>>()?;
    let Some(negative_case_count) = report
        .get("negative_case_count")
        .and_then(JsonValue::as_u64)
    else {
        return Err(format!(
            "{} verify-native-gpu-negative negative_case_count is missing",
            report_path.display()
        )
        .into());
    };
    if negative_case_count < required_ids.len() as u64 {
        return Err(format!(
            "{} verify-native-gpu-negative negative_case_count is smaller than required_negative_cases",
            report_path.display()
        )
        .into());
    }
    if required_ids.len() != required_ids.iter().copied().collect::<BTreeSet<_>>().len() {
        return Err(format!(
            "{} verify-native-gpu-negative required_negative_cases contains duplicates",
            report_path.display()
        )
        .into());
    }
    let present = required_ids.iter().copied().collect::<BTreeSet<_>>();
    let missing = native_gpu_product_path_negative_case_ids()
        .iter()
        .copied()
        .filter(|id| !present.contains(id))
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(format!(
            "{} verify-native-gpu-negative required_negative_cases missing product-path cases: {}",
            report_path.display(),
            missing.join(", ")
        )
        .into());
    }
    Ok(())
}

fn report_is_native_passive_scroll_command(report: &JsonValue) -> bool {
    report
        .get("command")
        .and_then(JsonValue::as_str)
        .is_some_and(|command| command.contains("scroll"))
        || report.get("passive_scroll_path_kind").is_some()
        || report
            .get("runtime_dispatch_count_for_passive_scroll")
            .is_some()
        || report.get("runtime_dispatch_on_passive_scroll").is_some()
}

fn collect_native_ux_product_path_reasons(
    value: &JsonValue,
    path: &str,
    passive_scroll: bool,
    reasons: &mut Vec<String>,
) {
    match value {
        JsonValue::Object(object) => {
            for (key, child) in object {
                let child_path = format!("{path}.{key}");
                if key == "render_loop_mode" && child.as_str() == Some("continuous_probe") {
                    reasons.push(format!(
                        "{child_path}=continuous_probe is forbidden for native UX reports"
                    ));
                }
                if native_ux_proof_required_bool_key(key) && child.as_bool() == Some(true) {
                    reasons.push(format!(
                        "{child_path}=true makes proof part of the visible update path"
                    ));
                }
                if native_ux_below_host_input_bool_key(key) && child.as_bool() == Some(true) {
                    reasons.push(format!(
                        "{child_path}=true injects input below HostEvent/HostInputEvent"
                    ));
                }
                if native_ux_forbidden_proof_bool_key(key) && child.as_bool() == Some(true) {
                    reasons.push(format!(
                        "{child_path}=true substitutes non-native proof for native UX evidence"
                    ));
                }
                if key == "dev_hot_path_counters" {
                    require_dev_preview_perf_hot_path_guards(child, &child_path, reasons);
                }
                if key == "cosmic_toplevel_probe"
                    && child.get("status").and_then(JsonValue::as_str) == Some("pass")
                {
                    reasons.push(format!(
                        "{child_path}.status=pass uses COSMIC toplevel scraping as native UX proof"
                    ));
                }
                if native_ux_hot_path_counter_key(key) && json_number_is_positive(child) {
                    reasons.push(format!("{child_path} must be zero for native UX reports"));
                }
                if native_ux_hot_path_bool_key(key) && child.as_bool() == Some(true) {
                    reasons.push(format!(
                        "{child_path}=true is forbidden in native UX hot paths"
                    ));
                }
                if key == "offscreen_app_owned_scene_readback_skipped"
                    && child.as_bool() == Some(false)
                {
                    reasons.push(format!(
                        "{child_path}=false means render-hook offscreen app-owned proof ran in a native UX hot path"
                    ));
                }
                if key == "render_backend_trait"
                    && child.as_str() == Some("boon_native_gpu::render_app_owned_scene_pixels")
                {
                    reasons.push(format!(
                        "{child_path}=boon_native_gpu::render_app_owned_scene_pixels runs render-hook offscreen app-owned proof in a native UX hot path"
                    ));
                }
                if passive_scroll
                    && native_ux_passive_scroll_counter_key(key)
                    && json_number_is_positive(child)
                {
                    reasons.push(format!(
                        "{child_path} must be zero for passive scroll native UX reports"
                    ));
                }
                if passive_scroll
                    && native_ux_passive_scroll_bool_key(key)
                    && child.as_bool() == Some(true)
                {
                    reasons.push(format!(
                        "{child_path}=true is forbidden for passive scroll native UX reports"
                    ));
                }
                if key == "input_injection_method"
                    && child
                        .as_str()
                        .is_some_and(native_ux_below_host_input_method)
                {
                    reasons.push(format!(
                        "{child_path} injects input below HostEvent/HostInputEvent"
                    ));
                }
                if native_ux_capture_method_key(key)
                    && child
                        .as_str()
                        .is_some_and(native_ux_forbidden_capture_method)
                {
                    reasons.push(format!(
                        "{child_path} uses non-native proof capture `{}`",
                        child.as_str().unwrap_or_default()
                    ));
                }
                collect_native_ux_product_path_reasons(child, &child_path, passive_scroll, reasons);
            }
        }
        JsonValue::Array(items) => {
            for (index, child) in items.iter().enumerate() {
                collect_native_ux_product_path_reasons(
                    child,
                    &format!("{path}[{index}]"),
                    passive_scroll,
                    reasons,
                );
            }
        }
        _ => {}
    }
}

fn collect_native_ux_proof_currentness_reasons(report: &JsonValue, reasons: &mut Vec<String>) {
    if report
        .get("proof_lag_frames")
        .and_then(JsonValue::as_u64)
        .is_some_and(|frames| frames > 0)
    {
        reasons.push("native UX proof must not lag the measured presented frame".to_owned());
    }
    for key in [
        "stale_for_latest_input",
        "readback_stale_for_latest_input",
        "last_interactive_surface_readback_pending",
        "last_interactive_readback_pending",
        "readback_pending_for_latest_input",
    ] {
        if report.get(key).and_then(JsonValue::as_bool) == Some(true) {
            reasons.push(format!(
                "{key}=true is forbidden for native UX proof currentness"
            ));
        }
    }
    let Some(artifact) = report.get("last_interactive_readback_artifact") else {
        return;
    };
    let app_owned_wgpu_readback = artifact
        .get("capture_method")
        .and_then(JsonValue::as_str)
        .is_some_and(native_app_owned_wgpu_readback_capture_method);
    if !app_owned_wgpu_readback {
        return;
    }
    if artifact
        .get("readback_poll_status")
        .and_then(JsonValue::as_str)
        .is_some_and(|status| status != "completed_before_deadline")
    {
        reasons.push(
            "last_interactive_readback_artifact must be completed before deadline for native UX"
                .to_owned(),
        );
    }
    if let (Some(root_key), Some(readback_key)) = (
        report.get("frame_evidence_key"),
        artifact.get("frame_evidence_key"),
    ) && root_key != readback_key
    {
        reasons.push(
            "last_interactive_readback_artifact.frame_evidence_key must match top-level frame_evidence_key for native UX"
                .to_owned(),
        );
    }
}

fn require_dev_preview_perf_hot_path_guards(
    value: &JsonValue,
    path: &str,
    reasons: &mut Vec<String>,
) {
    let Some(object) = value.as_object() else {
        reasons.push(format!("{path} must be an object"));
        return;
    };
    for key in [
        "preview_perf_hot_path_query_count",
        "dev_footer_preview_perf_hot_path_ipc_count",
        "footer_lines_preview_perf_ipc_count",
        "render_hook_preview_perf_ipc_count",
        "preview_perf_runtime_summary_query_count",
        "preview_perf_hot_path_runtime_query_count",
    ] {
        if object.get(key).and_then(JsonValue::as_u64).is_none() {
            reasons.push(format!("{path}.{key} must be an integer guard counter"));
        }
    }
    for key in [
        "dev_perf_row_queries_ipc_from_render_hook",
        "dev_perf_row_queries_runtime_from_render_hook",
        "preview_perf_snapshot_queried_in_render_hook",
        "preview_perf_snapshot_queried_in_footer_lines",
    ] {
        if object.get(key).and_then(JsonValue::as_bool).is_none() {
            reasons.push(format!("{path}.{key} must be a boolean guard"));
        }
    }
}

