    #[test]
    fn bytes_byte_bank_layout_schema_rejects_tampered_bank_payloads() {
        let report = bytes_byte_bank_layout_report();
        assert!(schema_accepts(
            report.clone(),
            "bytes-byte-bank-layout-valid"
        ));

        let mut missing_bank = report.clone();
        missing_bank["bytes_byte_bank_layout"]["cases"][0]["byte_banks"]
            .as_array_mut()
            .unwrap()
            .pop();
        assert!(!schema_accepts(
            missing_bank,
            "bytes-byte-bank-layout-missing-bank"
        ));

        let mut forged_count = report.clone();
        forged_count["bytes_byte_bank_layout"]["cases"][0]["byte_bank_count"] = json!(3);
        assert!(!schema_accepts(
            forged_count,
            "bytes-byte-bank-layout-forged-count"
        ));

        let mut bad_fixed_len = report.clone();
        bad_fixed_len["bytes_byte_bank_layout"]["cases"][2]["byte_banks"][0]["fixed_len"] =
            json!(4);
        assert!(!schema_accepts(
            bad_fixed_len,
            "bytes-byte-bank-layout-bad-fixed-len"
        ));

        let mut bad_indexed_flag = report;
        bad_indexed_flag["bytes_byte_bank_layout"]["cases"][2]["byte_banks"][0]["indexed"] =
            json!(false);
        assert!(!schema_accepts(
            bad_indexed_flag,
            "bytes-byte-bank-layout-bad-indexed-flag"
        ));
    }

    #[test]
    fn bytes_machine_plan_child_argv_accepts_boon_cli_run_source_replay_commands() {
        let source_replay_argv = json!([
            "target/debug/boon_cli",
            "run",
            "examples/todomvc.bn",
            "--scenario",
            "examples/todomvc.scn",
            "--report",
            "target/reports/bytes-plan/todomvc-scenario-events-full.json"
        ]);
        let source_replay_argv = source_replay_argv.as_array().unwrap();
        assert!(child_command_argv_proves_expected_command(
            source_replay_argv,
            "run-plan-scenario-events"
        ));
        assert!(!child_command_argv_proves_expected_command(
            source_replay_argv,
            "dump-plan"
        ));
        let retired_engine_argv = json!([
            "target/debug/boon_cli",
            "run",
            "examples/todomvc.bn",
            "--scenario",
            "examples/todomvc.scn",
            "--engine",
            "plan",
            "--report",
            "target/reports/bytes-plan/todomvc-scenario-events-full.json"
        ]);
        assert!(!child_command_argv_proves_expected_command(
            retired_engine_argv.as_array().unwrap(),
            "run-plan-scenario-events"
        ));

        let semantic_argv = json!([
            "target/debug/boon_cli",
            "run",
            "examples/cells.bn",
            "--scenario",
            "examples/cells.scn",
            "--report",
            "target/reports/bytes-plan/cells-ascii-formula-run.json"
        ]);
        let semantic_argv = semantic_argv.as_array().unwrap();
        assert!(child_command_argv_proves_expected_command(
            semantic_argv,
            "semantic"
        ));
        assert!(child_command_argv_proves_expected_command(
            semantic_argv,
            "run-plan-scenario-events"
        ));
    }

