    fn schema_accepts(report: JsonValue, name: &str) -> bool {
        let path = temp_report_path(name);
        write_json(&path, &report).unwrap();
        let accepted = verify_report_schema(&path).is_ok();
        let _ = fs::remove_file(path);
        accepted
    }

